/**
 * Activity Logs API Routes
 *
 * GET /api/activity-logs - Get activity logs with filtering
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { activityLogs, users } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, desc, like, type SQL } from "drizzle-orm";
import { getRecentActivity } from "@/services/activityLog";

// ============================================================================
// GET /api/activity-logs - Get activity logs
// ============================================================================()

export async function GET(request: NextRequest) {
  try {
    await requirePermission(PERMISSIONS.VIEW_ACTIVITY_LOGS);

    const { searchParams } = new URL(request.url);
    const action = searchParams.get("action");
    const entity = searchParams.get("entity");
    const userId = searchParams.get("userId");
    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "50");
    const offset = (page - 1) * limit;

    const db = getDb();

    // Build conditions
    const conditions: SQL[] = [];

    if (action) {
      conditions.push(eq(activityLogs.action, action));
    }

    if (entity) {
      conditions.push(eq(activityLogs.entity, entity));
    }

    if (userId) {
      conditions.push(eq(activityLogs.userId, userId));
    }

    // Get total count
    const countQuery = db
      .select({ count: sql<number>`count(*)::int` })
      .from(activityLogs);

    if (conditions.length > 0) {
      countQuery.where(and(...conditions));
    }

    const countResult = await countQuery;

    const total = countResult[0]?.count || 0;

    // Get logs with user details
    const logsQuery = db
      .select({
        id: activityLogs.id,
        userId: activityLogs.userId,
        action: activityLogs.action,
        entity: activityLogs.entity,
        entityId: activityLogs.entityId,
        metadata: activityLogs.metadata,
        ipAddress: activityLogs.ipAddress,
        createdAt: activityLogs.createdAt,
        userName: users.name,
        userEmail: users.email,
        userRole: users.role,
      })
      .from(activityLogs)
      .leftJoin(users, eq(activityLogs.userId, users.id))
      .orderBy(desc(activityLogs.createdAt))
      .limit(limit)
      .offset(offset);

    if (conditions.length > 0) {
      logsQuery.where(and(...conditions));
    }

    const logs = await logsQuery;

    return NextResponse.json({
      success: true,
      data: logs.map((log) => ({
        id: log.id,
        userId: log.userId,
        action: log.action,
        entity: log.entity,
        entityId: log.entityId,
        metadata: log.metadata as Record<string, unknown> | null,
        ipAddress: log.ipAddress,
        createdAt: log.createdAt,
        user: log.userName
          ? {
              name: log.userName,
              email: log.userEmail || "",
              role: log.userRole as "admin" | "staff",
            }
          : null,
      })),
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Get activity logs error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Database Reset API Route
 *
 * POST /api/admin/reset-data - Clear all data (admin only)
 *
 * Deletes all records from tables while keeping users and sessions intact.
 * Tables are deleted in order to respect foreign key constraints.
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";

export async function POST(request: NextRequest) {
  try {
    // Only admins can reset data
    const user = await requirePermission(PERMISSIONS.MANAGE_STAFF);
    if (user.role !== "admin") {
      return NextResponse.json(
        { success: false, error: "Only admins can reset database" },
        { status: 403 }
      );
    }

    const db = getDb();

    // Delete in order to respect foreign key constraints
    // Child tables first, then parent tables
    const tablesToDelete = [
      // Order-related (child tables first)
      "order_delivery_snapshots",
      "order_items",
      "orders",
      // Inventory-related (child tables first)
      "inventory_items",
      "inventory_batches",
      // Coupon-related (child tables first)
      "coupon_usage",
      "coupons",
      // Product-related (child tables first)
      "product_platform_links",
      "product_images",
      "products",
      // Templates and platforms
      "inventory_templates",
      "platforms",
      // Logs and analytics
      "activity_logs",
      "daily_analytics",
      // Reviews
      "reviews",
    ];

    const deletedCounts: Record<string, number> = {};

    for (const table of tablesToDelete) {
      const result = await db.execute(
        // Using TRUNCATE for efficiency, CASCADE to handle any remaining FK constraints
        // and RESTART IDENTITY to reset sequences
        // Also filtering out soft-deleted records
        `DELETE FROM ${table} RETURNING *`
      );
      deletedCounts[table] = result.rowCount ?? 0;
    }

    return NextResponse.json({
      success: true,
      data: {
        message: "Database reset successfully",
        deletedCounts,
        tablesProcessed: tablesToDelete.length,
        timestamp: new Date().toISOString(),
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Database reset error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error", details: error instanceof Error ? error.message : String(error) },
      { status: 500 }
    );
  }
}

/**
 * Analytics API Routes
 *
 * GET /api/analytics - Get dashboard analytics data
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { orders, products, orderItems } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { sql, and, gte, lte } from "drizzle-orm";

// ============================================================================
// GET /api/analytics - Get analytics data
// ============================================================================()

export async function GET(request: NextRequest) {
  try {
    await requirePermission(PERMISSIONS.VIEW_ANALYTICS);

    const { searchParams } = new URL(request.url);
    const period = searchParams.get("period") || "30"; // days

    const db = getDb();

    // Calculate date range
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const weekAgo = new Date(today.getTime() - 7 * 24 * 60 * 60 * 1000);
    const monthAgo = new Date(today.getTime() - 30 * 24 * 60 * 60 * 1000);

    // Get total revenue (all time)
    const [totalRevenue] = await db
      .select({
        revenue: sql<number>`COALESCE(SUM(total), 0)::numeric`,
      })
      .from(orders)
      .where(
        and(
          sql`status = 'completed'`,
          sql`deleted_at IS NULL`
        )
      );

    // Get today's revenue
    const [todayRevenue] = await db
      .select({
        revenue: sql<number>`COALESCE(SUM(total), 0)::numeric`,
      })
      .from(orders)
      .where(
        and(
          sql`status = 'completed'`,
          gte(orders.createdAt, today),
          sql`deleted_at IS NULL`
        )
      );

    // Get this week's revenue
    const [weekRevenue] = await db
      .select({
        revenue: sql<number>`COALESCE(SUM(total), 0)::numeric`,
      })
      .from(orders)
      .where(
        and(
          sql`status = 'completed'`,
          gte(orders.createdAt, weekAgo),
          sql`deleted_at IS NULL`
        )
      );

    // Get this month's revenue
    const [monthRevenue] = await db
      .select({
        revenue: sql<number>`COALESCE(SUM(total), 0)::numeric`,
      })
      .from(orders)
      .where(
        and(
          sql`status = 'completed'`,
          gte(orders.createdAt, monthAgo),
          sql`deleted_at IS NULL`
        )
      );

    // Get order counts
    const [totalOrders] = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(orders)
      .where(sql`deleted_at IS NULL`);

    const [todayOrders] = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(orders)
      .where(and(gte(orders.createdAt, today), sql`deleted_at IS NULL`));

    const [pendingOrders] = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(orders)
      .where(
        and(
          sql`status = 'pending'`,
          sql`deleted_at IS NULL`
        )
      );

    const [completedOrders] = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(orders)
      .where(
        and(
          sql`status = 'completed'`,
          sql`deleted_at IS NULL`
        )
      );

    // Get product stats
    const [totalProducts] = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(products)
      .where(sql`deleted_at IS NULL`);

    const [activeProducts] = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(products)
      .where(
        and(
          sql`is_active = true`,
          sql`deleted_at IS NULL`
        )
      );

    // Get low stock products (less than 5 items)
    const lowStockProducts = await db
      .select({
        id: products.id,
        name: products.name,
        stockCount: products.stockCount,
      })
      .from(products)
      .where(
        and(
          sql`stock_count < 5`,
          sql`is_active = true`,
          sql`deleted_at IS NULL`
        )
      )
      .orderBy(products.stockCount)
      .limit(10);

    // Get top selling products
    const topProducts = await db
      .select({
        id: products.id,
        name: products.name,
        slug: products.slug,
        totalSold: products.totalSold,
        revenue: sql<number>`(total_sold * price)::numeric`,
      })
      .from(products)
      .where(
        and(
          sql`is_active = true`,
          sql`deleted_at IS NULL`
        )
      )
      .orderBy(sql`total_sold DESC`)
      .limit(5);

    // Get sales chart data (daily for the period)
    const daysInPeriod = parseInt(period);
    const salesChartData = [];

    for (let i = daysInPeriod - 1; i >= 0; i--) {
      const date = new Date(today);
      date.setDate(date.getDate() - i);
      const startDate = new Date(date);
      const endDate = new Date(date);
      endDate.setDate(endDate.getDate() + 1);

      const [dayStats] = await db
        .select({
          revenue: sql<string>`COALESCE(SUM(total), '0')`,
          orders: sql<number>`count(*)`,
        })
        .from(orders)
        .where(
          and(
            gte(orders.createdAt, startDate),
            sql`created_at < ${endDate}`,
            sql`status = 'completed'`,
            sql`deleted_at IS NULL`
          )
        );

      salesChartData.push({
        date: date.toISOString().split("T")[0],
        revenue: dayStats.revenue,
        orders: dayStats.orders,
      });
    }

    return NextResponse.json({
      success: true,
      data: {
        revenue: {
          total: totalRevenue?.revenue?.toString() || "0",
          today: todayRevenue?.revenue?.toString() || "0",
          thisWeek: weekRevenue?.revenue?.toString() || "0",
          thisMonth: monthRevenue?.revenue?.toString() || "0",
        },
        orders: {
          total: totalOrders?.count || 0,
          today: todayOrders?.count || 0,
          pending: pendingOrders?.count || 0,
          completed: completedOrders?.count || 0,
        },
        products: {
          total: totalProducts?.count || 0,
          active: activeProducts?.count || 0,
          lowStock: lowStockProducts,
          topSellers: topProducts,
        },
        salesChart: salesChartData,
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Get analytics error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Coupons API Routes
 *
 * GET /api/coupons - List all coupons
 * POST /api/coupons - Create a new coupon
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { coupons, couponUsage } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, desc } from "drizzle-orm";
import { logCouponCreated } from "@/services/activityLog";

// ============================================================================
// GET /api/coupons - List coupons
// ============================================================================()

export async function GET(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.VIEW_ANALYTICS);

    const { searchParams } = new URL(request.url);
    const isActive = searchParams.get("isActive");
    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "20");
    const offset = (page - 1) * limit;

    const db = getDb();

    // Build conditions
    const conditions = [sql`deleted_at IS NULL`];

    if (isActive !== null && isActive !== "") {
      conditions.push(eq(coupons.isActive, isActive === "true"));
    }

    // Get total count
    const countResult = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(coupons)
      .where(and(...conditions));

    const total = countResult[0]?.count || 0;

    // Get coupons
    const couponsList = await db
      .select()
      .from(coupons)
      .where(and(...conditions))
      .orderBy(desc(coupons.createdAt))
      .limit(limit)
      .offset(offset);

    return NextResponse.json({
      success: true,
      data: couponsList,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Get coupons error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ============================================================================
// POST /api/coupons - Create coupon
// ============================================================================()

export async function POST(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.MANAGE_COUPONS);

    const body = await request.json();
    const {
      code,
      description,
      discountType,
      discountValue,
      minPurchase = "0",
      maxDiscount,
      usageLimit,
      userLimit = 1,
      validFrom,
      validUntil,
      applicableProductIds,
    } = body;

    // Validate input
    if (!code || !discountType || !discountValue) {
      return NextResponse.json(
        { success: false, error: "Code, discountType, and discountValue are required" },
        { status: 400 }
      );
    }

    if (!["percentage", "fixed"].includes(discountType)) {
      return NextResponse.json(
        { success: false, error: "discountType must be 'percentage' or 'fixed'" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Check if code already exists
    const [existing] = await db
      .select()
      .from(coupons)
      .where(eq(coupons.code, code.toUpperCase()))
      .limit(1);

    if (existing) {
      return NextResponse.json(
        { success: false, error: "Coupon with this code already exists" },
        { status: 409 }
      );
    }

    // Create coupon
    const [coupon] = await db
      .insert(coupons)
      .values({
        code: code.toUpperCase(),
        description,
        discountType,
        discountValue: discountValue.toString(),
        minPurchase: minPurchase.toString(),
        maxDiscount: maxDiscount?.toString(),
        usageLimit,
        userLimit,
        validFrom: validFrom || new Date(),
        validUntil,
        applicableProductIds,
        isActive: true,
      })
      .returning();

    // Log activity
    await logCouponCreated(user.id, coupon.id, coupon.code);

    return NextResponse.json({
      success: true,
      data: coupon,
    }, { status: 201 });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Create coupon error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Inventory Batches API
 *
 * GET /api/inventory/batches - List batches
 * POST /api/inventory/batches - Create a new batch
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { inventoryBatches, inventoryItems, products, users } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, desc } from "drizzle-orm";
import { logActivity } from "@/services/activityLog";

// ============================================================================
// GET /api/inventory/batches - List batches
// ============================================================================

export async function GET(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.MANAGE_INVENTORY);

    const { searchParams } = new URL(request.url);
    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "20");
    const offset = (page - 1) * limit;

    const db = getDb();

    // Get total count
    const countResult = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(inventoryBatches)
      .where(sql`${inventoryBatches.deletedAt} IS NULL`);

    const total = countResult[0]?.count || 0;

    // Get batches with item counts
    const batches = await db
      .select({
        id: inventoryBatches.id,
        name: inventoryBatches.name,
        source: inventoryBatches.source,
        notes: inventoryBatches.notes,
        createdBy: inventoryBatches.createdBy,
        createdAt: inventoryBatches.createdAt,
        createdByName: users.name,
        // Count items in this batch
        itemCount: sql<number>`(
          SELECT COUNT(*)::int
          FROM inventory_items
          WHERE inventory_items.batch_id = inventory_batches.id
            AND inventory_items.deleted_at IS NULL
        )`,
      })
      .from(inventoryBatches)
      .leftJoin(users, eq(inventoryBatches.createdBy, users.id))
      .where(sql`${inventoryBatches.deletedAt} IS NULL`)
      .orderBy(desc(inventoryBatches.createdAt))
      .limit(limit)
      .offset(offset);

    return NextResponse.json({
      success: true,
      data: batches,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Get batches error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ============================================================================
// POST /api/inventory/batches - Create batch
// ============================================================================

export async function POST(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.MANAGE_INVENTORY);

    const body = await request.json();
    const { name, source, notes } = body;

    // Validate input
    if (!name || name.trim().length === 0) {
      return NextResponse.json(
        { success: false, error: "Name is required" },
        { status: 400 }
      );
    }

    const db = getDb();

    const [newBatch] = await db
      .insert(inventoryBatches)
      .values({
        name: name.trim(),
        source: source || null,
        notes: notes || null,
        createdBy: user.id,
      })
      .returning();

    // Log activity
    await logActivity({
      userId: user.id,
      action: "batch_created",
      entity: "inventory_batch",
      entityId: newBatch.id,
      metadata: { name: newBatch.name, source },
    });

    return NextResponse.json({
      success: true,
      data: newBatch,
    }, { status: 201 });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Create batch error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Inventory Export API
 *
 * GET /api/inventory/export - Export available inventory as TSV/CSV
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { inventoryItems, products, inventoryTemplates } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, desc } from "drizzle-orm";

export async function GET(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.MANAGE_INVENTORY);

    const { searchParams } = new URL(request.url);
    const productId = searchParams.get("productId");
    const format = searchParams.get("format") || "tsv"; // tsv or csv

    if (!productId) {
      return NextResponse.json(
        { success: false, error: "Product ID is required" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Get product and template
    const [product] = await db
      .select({
        id: products.id,
        name: products.name,
        templateId: inventoryTemplates.id,
        fieldsSchema: inventoryTemplates.fieldsSchema,
      })
      .from(products)
      .innerJoin(inventoryTemplates, eq(products.inventoryTemplateId, inventoryTemplates.id))
      .where(eq(products.id, productId))
      .limit(1);

    if (!product) {
      return NextResponse.json(
        { success: false, error: "Product not found" },
        { status: 404 }
      );
    }

    // Get available inventory
    const inventory = await db
      .select({
        values: inventoryItems.values,
      })
      .from(inventoryItems)
      .where(
        and(
          eq(inventoryItems.productId, productId),
          eq(inventoryItems.status, "available"),
          sql`${inventoryItems.deletedAt} IS NULL`
        )
      )
      .orderBy(desc(inventoryItems.createdAt));

    // Get field names from template schema
    const fields = product.fieldsSchema || [];
    const fieldNames = fields.map((f: any) => f.name);

    // Build output
    const separator = format === "csv" ? "," : "\t";
    const rows: string[] = [];

    // Header row
    rows.push(fieldNames.join(separator));

    // Data rows
    for (const item of inventory) {
      const row = fieldNames.map((name: string) => {
        const value = (item.values as Record<string, unknown> | null)?.[name];
        // Escape quotes and wrap in quotes for CSV
        if (format === "csv") {
          const strValue = String(value ?? "");
          return `"${strValue.replace(/"/g, '""')}"`;
        }
        return String(value ?? "");
      });
      rows.push(row.join(separator));
    }

    const content = rows.join("\n");
    const contentType = format === "csv"
      ? "text/csv"
      : "text/tab-separated-values";

    return new NextResponse(content, {
      status: 200,
      headers: {
        "Content-Type": contentType,
        "Content-Disposition": `attachment; filename="${product.name.replace(/[^a-z0-9]/gi, '_')}_inventory.${format}"`,
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Export inventory error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Pending Inventory Count API
 *
 * GET /api/inventory/pending-count?productId=xxx - Get count of pending items needed for this product
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { orders, orderItems, products } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql } from "drizzle-orm";

export async function GET(request: NextRequest) {
  try {
    await requirePermission(PERMISSIONS.VIEW_PRODUCTS);

    const { searchParams } = new URL(request.url);
    const productId = searchParams.get("productId");

    if (!productId) {
      return NextResponse.json(
        { success: false, error: "Product ID is required" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Count pending items for this product
    // Pending items are those in orders with status='pending' or fulfillmentStatus='processing'
    // where the order item quantity > delivered inventory count
    const result = await db
      .select({
        totalRequested: sql<number>`sum(${orderItems.quantity})::int`,
        totalDelivered: sql<number>`sum(array_length(${orderItems.deliveredInventoryIds}, 1))::int`,
        pendingOrdersCount: sql<number>`count(distinct ${orders.id})::int`,
      })
      .from(orderItems)
      .innerJoin(orders, eq(orderItems.orderId, orders.id))
      .where(
        and(
          eq(orderItems.productId, productId),
          sql`${orders.deletedAt} IS NULL`,
          sql`(${orders.status} = 'pending' OR ${orders.fulfillmentStatus} = 'processing')`
        )
      );

    const data = result[0];
    const totalRequested = data?.totalRequested || 0;
    const totalDelivered = data?.totalDelivered || 0;
    const pendingItems = Math.max(0, totalRequested - totalDelivered);
    const pendingOrdersCount = data?.pendingOrdersCount || 0;

    return NextResponse.json({
      success: true,
      data: {
        productId,
        pendingItems,
        pendingOrdersCount,
        totalRequested,
        totalDelivered,
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Pending count error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Inventory API Routes
 *
 * GET /api/inventory - List inventory items with filtering
 * POST /api/inventory - Add new inventory items
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { inventoryItems, products, inventoryBatches } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, desc, like, or } from "drizzle-orm";
import { logInventoryAdded, logActivity } from "@/services/activityLog";

// ============================================================================
// GET /api/inventory - List inventory
// ============================================================================()

export async function GET(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.VIEW_PRODUCTS);

    const { searchParams } = new URL(request.url);
    const productId = searchParams.get("productId");
    const status = searchParams.get("status");
    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "50");
    const offset = (page - 1) * limit;

    const db = getDb();

    // Build conditions
    const conditions = [
      sql`${inventoryItems.deletedAt} IS NULL`,
      sql`${products.deletedAt} IS NULL`,
    ];

    if (productId) {
      conditions.push(eq(inventoryItems.productId, productId));
    }

    if (status) {
      conditions.push(eq(inventoryItems.status, status as "available" | "reserved" | "sold" | "expired"));
    }

    // Get total count (need to join products to filter deleted products)
    const countResult = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(inventoryItems)
      .innerJoin(products, eq(inventoryItems.productId, products.id))
      .where(and(...conditions));

    const total = countResult[0]?.count || 0;

    // Get inventory with product details
    const inventory = await db
      .select({
        id: inventoryItems.id,
        templateId: inventoryItems.templateId,
        productId: inventoryItems.productId,
        values: inventoryItems.values,
        status: inventoryItems.status,
        orderItemId: inventoryItems.orderItemId,
        reservedUntil: inventoryItems.reservedUntil,
        purchasedAt: inventoryItems.purchasedAt,
        createdAt: inventoryItems.createdAt,
        updatedAt: inventoryItems.updatedAt,
        productName: products.name,
        productSlug: products.slug,
      })
      .from(inventoryItems)
      .innerJoin(products, eq(inventoryItems.productId, products.id))
      .where(and(...conditions))
      .orderBy(desc(inventoryItems.createdAt))
      .limit(limit)
      .offset(offset);

    return NextResponse.json({
      success: true,
      data: inventory,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Get inventory error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ============================================================================
// POST /api/inventory - Add inventory items in bulk
// ============================================================================()

export async function POST(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.MANAGE_INVENTORY);

    const body = await request.json();
    const { productId, items, batchId, batchName } = body;

    // Validate input
    if (!productId || !Array.isArray(items) || items.length === 0) {
      return NextResponse.json(
        { success: false, error: "Product ID and items array are required" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Verify product exists and get template ID
    const [product] = await db
      .select({
        id: products.id,
        name: products.name,
        inventoryTemplateId: products.inventoryTemplateId,
      })
      .from(products)
      .where(eq(products.id, productId))
      .limit(1);

    if (!product) {
      return NextResponse.json(
        { success: false, error: "Product not found" },
        { status: 404 }
      );
    }

    if (!product.inventoryTemplateId) {
      return NextResponse.json(
        { success: false, error: "Product has no inventory template configured" },
        { status: 400 }
      );
    }

    // Determine batch ID - use existing or create new
    let finalBatchId = batchId;
    if (batchName && !batchId) {
      // Auto-create batch
      const [newBatch] = await db
        .insert(inventoryBatches)
        .values({
          name: batchName,
          source: "manual_import",
          createdBy: user.id,
        })
        .returning();
      finalBatchId = newBatch.id;
    } else if (batchId) {
      // Validate batch exists
      const [batch] = await db
        .select()
        .from(inventoryBatches)
        .where(
          and(
            eq(inventoryBatches.id, batchId),
            sql`${inventoryBatches.deletedAt} IS NULL`
          )
        )
        .limit(1);

      if (!batch) {
        return NextResponse.json(
          { success: false, error: "Batch not found" },
          { status: 404 }
        );
      }
    }

    // Insert inventory items
    const insertedItems = await db
      .insert(inventoryItems)
      .values(
        items.map((values: Record<string, unknown>) => ({
          productId,
          templateId: product.inventoryTemplateId!,
          batchId: finalBatchId || null,
          values,
          status: "available" as const,
        }))
      )
      .returning();

    // Update product stock count
    await db
      .update(products)
      .set({
        stockCount: sql`${products.stockCount} + ${items.length}`,
        updatedAt: new Date(),
      })
      .where(eq(products.id, productId));

    // Log activity (log once per batch)
    await logActivity({
      userId: user.id,
      action: "inventory_added",
      entity: "inventory",
      entityId: insertedItems[0].id,
      metadata: {
        productId,
        productName: product.name,
        quantity: items.length,
        batchId: finalBatchId,
        batchName,
      },
    });

    return NextResponse.json({
      success: true,
      data: {
        count: insertedItems.length,
        items: insertedItems,
        batchId: finalBatchId,
      },
    }, { status: 201 });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Add inventory error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Global Inventory Search API - Emergency search across all products
 *
 * GET /api/inventory/search - Search inventory by values across all products
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { inventoryItems, products, inventoryTemplates, inventoryBatches, users } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, or, like, desc } from "drizzle-orm";

export async function GET(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.MANAGE_INVENTORY);

    const { searchParams } = new URL(request.url);
    const query = searchParams.get("q");
    const status = searchParams.get("status");
    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "50");
    const offset = (page - 1) * limit;

    if (!query || query.trim().length === 0) {
      return NextResponse.json(
        { success: false, error: "Search query is required" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Build conditions - search in JSONB values
    const conditions = [
      sql`inventory_items.deleted_at IS NULL`,
      sql`products.deleted_at IS NULL`,
      // Cast JSONB to text for ILIKE search
      sql`inventory_items.values::text ILIKE ${`%${query.trim()}%`}`,
    ];

    if (status) {
      conditions.push(eq(inventoryItems.status, status as "available" | "reserved" | "sold" | "expired"));
    }

    // Get total count
    const countResult = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(inventoryItems)
      .innerJoin(products, eq(inventoryItems.productId, products.id))
      .where(and(...conditions));

    const total = countResult[0]?.count || 0;

    // Get matching inventory items
    const inventory = await db
      .select({
        id: inventoryItems.id,
        values: inventoryItems.values,
        status: inventoryItems.status,
        createdAt: inventoryItems.createdAt,
        purchasedAt: inventoryItems.purchasedAt,
        productId: inventoryItems.productId,
        productName: products.name,
        productSlug: products.slug,
        templateName: inventoryTemplates.name,
        batchName: inventoryBatches.name,
      })
      .from(inventoryItems)
      .innerJoin(products, eq(inventoryItems.productId, products.id))
      .leftJoin(inventoryTemplates, eq(inventoryItems.templateId, inventoryTemplates.id))
      .leftJoin(inventoryBatches, eq(inventoryItems.batchId, inventoryBatches.id))
      .where(and(...conditions))
      .orderBy(desc(inventoryItems.createdAt))
      .limit(limit)
      .offset(offset);

    return NextResponse.json({
      success: true,
      data: inventory,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Inventory search error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

