/**
 * Add Inventory to Pending Order API Route
 *
 * POST /api/orders/[id]/add-inventory - Quick endpoint to add inventory and fulfill pending order
 *
 * This is a streamlined endpoint that:
 * 1. Auto-claims the order if not claimed
 * 2. Creates inventory items in bulk
 * 3. Immediately fulfills pending items with the new inventory
 * 4. Releases the claim if order is completed
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { orders, orderItems, inventoryItems, products } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, inArray } from "drizzle-orm";
import { logActivity } from "@/services/activityLog";
import { getOrderDeliveryData } from "@/services/autoDelivery";

interface AddInventoryRequest {
  productId: string;
  quantity: number;
  values: Record<string, string | number | boolean>;
}

type RouteContext = {
  params: Promise<{ id: string }>;
};

export async function POST(request: NextRequest, context: RouteContext) {
  try {
    const user = await requirePermission(PERMISSIONS.PROCESS_ORDERS);
    const isAdmin = user.role === "admin";
    const { id: orderId } = await context.params;

    const body: AddInventoryRequest = await request.json();
    const { productId, quantity, values } = body;

    // Validate input
    if (!productId) {
      return NextResponse.json(
        { success: false, error: "Product ID is required" },
        { status: 400 }
      );
    }

    if (!quantity || quantity <= 0) {
      return NextResponse.json(
        { success: false, error: "Quantity must be greater than 0" },
        { status: 400 }
      );
    }

    if (!values || Object.keys(values).length === 0) {
      return NextResponse.json(
        { success: false, error: "Inventory values are required" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Get order and check status
    const [order] = await db
      .select({
        id: orders.id,
        status: orders.status,
        fulfillmentStatus: orders.fulfillmentStatus,
        claimedBy: orders.claimedBy,
        claimedAt: orders.claimedAt,
        claimExpiresAt: orders.claimExpiresAt,
      })
      .from(orders)
      .where(and(eq(orders.id, orderId), sql`deleted_at IS NULL`))
      .limit(1);

    if (!order) {
      return NextResponse.json(
        { success: false, error: "Order not found" },
        { status: 404 }
      );
    }

    // Check if order is in pending/processing status
    if (order.status !== "pending" || order.fulfillmentStatus !== "processing") {
      return NextResponse.json(
        { success: false, error: "Order is not in pending status" },
        { status: 400 }
      );
    }

    // Auto-claim order if not claimed
    if (!order.claimedBy) {
      const CLAIM_TTL_MINUTES = 30;
      const claimExpiresAt = new Date(Date.now() + CLAIM_TTL_MINUTES * 60 * 1000);

      await db
        .update(orders)
        .set({
          claimedBy: user.id,
          claimedAt: new Date(),
          claimExpiresAt,
          updatedAt: new Date(),
        })
        .where(eq(orders.id, orderId));

      await logActivity({
        userId: user.id,
        action: "order_claimed",
        entity: "order",
        entityId: orderId,
        metadata: { autoClaimed: true },
      });
    }

    // Check claim enforcement
    const isClaimExpired = order.claimExpiresAt && order.claimExpiresAt < new Date();
    const isClaimedByMe = order.claimedBy === user.id;
    const isClaimedByOther = order.claimedBy && !isClaimedByMe && !isClaimExpired;

    if (!isAdmin && isClaimedByOther) {
      return NextResponse.json(
        { success: false, error: "Order is claimed by another staff member" },
        { status: 403 }
      );
    }

    // Get product info
    const [product] = await db
      .select({
        id: products.id,
        name: products.name,
        inventoryTemplateId: products.inventoryTemplateId,
      })
      .from(products)
      .where(eq(products.id, productId))
      .limit(1);

    if (!product) {
      return NextResponse.json(
        { success: false, error: "Product not found" },
        { status: 404 }
      );
    }

    // Process inventory addition and fulfillment
    const result = await db.transaction(async (tx) => {
      // Find the order item for this product
      const [orderItem] = await tx
        .select({
          id: orderItems.id,
          quantity: orderItems.quantity,
          deliveredInventoryIds: orderItems.deliveredInventoryIds,
        })
        .from(orderItems)
        .where(and(eq(orderItems.orderId, orderId), eq(orderItems.productId, productId)))
        .limit(1);

      if (!orderItem) {
        throw new Error("Product not found in order items");
      }

      const currentlyDelivered = (orderItem.deliveredInventoryIds || []).length;
      const stillNeeded = orderItem.quantity - currentlyDelivered;
      const toFulfillNow = Math.min(quantity, stillNeeded);

      // Create all requested inventory items
      const newInventoryIds: string[] = [];
      for (let i = 0; i < quantity; i++) {
        const [inserted] = await tx
          .insert(inventoryItems)
          .values({
            productId,
            templateId: product.inventoryTemplateId!,
            values,
            status: "sold",
            purchasedAt: new Date(),
            // Only link to order item for items being fulfilled now
            orderItemId: i < toFulfillNow ? orderItem.id : null,
          })
          .returning();

        newInventoryIds.push(inserted.id);
      }

      // Update order item with newly fulfilled inventory
      let updatedDeliveredIds = [...(orderItem.deliveredInventoryIds || [])];
      const newlyFulfilledIds = newInventoryIds.slice(0, toFulfillNow);
      updatedDeliveredIds.push(...newlyFulfilledIds);

      await tx
        .update(orderItems)
        .set({
          deliveredInventoryIds: sql`${JSON.stringify(updatedDeliveredIds)}::jsonb`,
        })
        .where(eq(orderItems.id, orderItem.id));

      // Update product stats (only count items that were sold)
      await tx
        .update(products)
        .set({
          totalSold: sql`${products.totalSold} + ${toFulfillNow}`,
          updatedAt: new Date(),
        })
        .where(eq(products.id, productId));

      // Calculate remaining needed across all order items
      const allOrderItems = await tx
        .select({
          id: orderItems.id,
          quantity: orderItems.quantity,
          deliveredInventoryIds: orderItems.deliveredInventoryIds,
        })
        .from(orderItems)
        .where(eq(orderItems.orderId, orderId));

      let allFulfilled = true;
      for (const item of allOrderItems) {
        const delivered = (item.deliveredInventoryIds || []).length;
        if (delivered < item.quantity) {
          allFulfilled = false;
          break;
        }
      }

      // Update order status if all items fulfilled
      let updatedOrder = order;
      if (allFulfilled) {
        [updatedOrder] = await tx
          .update(orders)
          .set({
            status: "completed",
            fulfillmentStatus: "delivered",
            deliveredAt: new Date(),
            claimedBy: null,
            claimedAt: null,
            claimExpiresAt: null,
            updatedAt: new Date(),
          })
          .where(eq(orders.id, orderId))
          .returning();

        // Update delivery snapshot
        const deliveryData = await getOrderDeliveryData(orderId);
        await tx.execute(
          sql`
            UPDATE order_delivery_snapshots
            SET payload = ${JSON.stringify(deliveryData)}::jsonb
            WHERE order_id = ${orderId}
          `
        );
      }

      return {
        order: updatedOrder,
        orderItem: {
          id: orderItem.id,
          totalNeeded: orderItem.quantity,
          previouslyDelivered: currentlyDelivered,
          newlyFulfilled: toFulfillNow,
          remainingNeeded: stillNeeded - toFulfillNow,
        },
        inventoryCreated: quantity,
        inventoryRemaining: quantity - toFulfillNow,
        allFulfilled,
      };
    });

    // Log activity
    await logActivity({
      userId: user.id,
      action: result.allFulfilled ? "order_completed" : "inventory_added",
      entity: "order",
      entityId: orderId,
      metadata: {
        productId,
        inventoryCreated: result.inventoryCreated,
        newlyFulfilled: result.orderItem.newlyFulfilled,
        inventoryRemaining: result.inventoryRemaining,
      },
    });

    return NextResponse.json({
      success: true,
      data: {
        order: result.order,
        summary: {
          product: product.name,
          inventoryCreated: result.inventoryCreated,
          newlyFulfilled: result.orderItem.newlyFulfilled,
          totalNeeded: result.orderItem.totalNeeded,
          remainingNeeded: result.orderItem.remainingNeeded,
          inventoryRemaining: result.inventoryRemaining,
        },
        allFulfilled: result.allFulfilled,
        message: result.allFulfilled
          ? `Order completed! Added ${result.inventoryCreated} item(s).`
          : `Added ${result.inventoryCreated} item(s). ${result.orderItem.remainingNeeded} more needed for this product.`,
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
      if (error.message === "Product not found in order items") {
        return NextResponse.json(
          { success: false, error: "Product not found in this order" },
          { status: 400 }
        );
      }
    }

    console.error("Add inventory error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Pending Order Fulfillment API Route
 *
 * POST /api/orders/[id]/fulfill-pending - Add inventory to pending order and fulfill items
 *
 * This endpoint allows adding new inventory items to a pending order.
 * Extra items (beyond what's needed) become available inventory.
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { orders, orderItems, inventoryItems, products, users } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql } from "drizzle-orm";
import { logActivity } from "@/services/activityLog";
import { getOrderDeliveryData } from "@/services/autoDelivery";

interface InventoryItemRequest {
  productId: string;
  values: Record<string, string | number | boolean>;
}

interface FulfillPendingRequest {
  inventoryItems: InventoryItemRequest[];
}

type RouteContext = {
  params: Promise<{ id: string }>;
};

export async function POST(request: NextRequest, context: RouteContext) {
  try {
    const user = await requirePermission(PERMISSIONS.PROCESS_ORDERS);
    const isAdmin = user.role === "admin";
    const { id: orderId } = await context.params;

    const body: FulfillPendingRequest = await request.json();
    const { inventoryItems: inputInventoryItems = [] } = body;

    // Validate and filter input
    const validInventoryItems = inputInventoryItems.filter(
      (item) => item && item.productId && item.values && typeof item.values === "object"
    );

    if (validInventoryItems.length === 0) {
      return NextResponse.json(
        { success: false, error: "Valid inventory items are required" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Get order with claim info
    const [order] = await db
      .select({
        id: orders.id,
        status: orders.status,
        fulfillmentStatus: orders.fulfillmentStatus,
        claimedBy: orders.claimedBy,
        claimedAt: orders.claimedAt,
        claimExpiresAt: orders.claimExpiresAt,
        customerEmail: orders.customerEmail,
      })
      .from(orders)
      .where(and(eq(orders.id, orderId), sql`deleted_at IS NULL`))
      .limit(1);

    if (!order) {
      return NextResponse.json(
        { success: false, error: "Order not found" },
        { status: 404 }
      );
    }

    // Check if order is in pending status
    if (order.status !== "pending" || order.fulfillmentStatus !== "processing") {
      return NextResponse.json(
        { success: false, error: "Order must be in pending status with processing fulfillment" },
        { status: 400 }
      );
    }

    // Check claim enforcement
    const isClaimExpired = order.claimExpiresAt && order.claimExpiresAt < new Date();
    const isClaimedByMe = order.claimedBy === user.id;
    const isClaimedByOther = order.claimedBy && !isClaimedByMe && !isClaimExpired;

    if (!isAdmin && isClaimedByOther) {
      // Get claimant name
      const [claimant] = await db
        .select({ name: users.name })
        .from(users)
        .where(eq(users.id, order.claimedBy!))
        .limit(1);

      return NextResponse.json(
        {
          success: false,
          error: "Order is claimed by another staff member",
          claimedBy: claimant?.name || "Unknown",
        },
        { status: 403 }
      );
    }

    // Get order items to determine what needs fulfillment
    const orderItemsData = await db
      .select({
        id: orderItems.id,
        productId: orderItems.productId,
        quantity: orderItems.quantity,
        deliveredInventoryIds: orderItems.deliveredInventoryIds,
        productName: products.name,
        inventoryTemplateId: products.inventoryTemplateId,
      })
      .from(orderItems)
      .innerJoin(products, eq(orderItems.productId, products.id))
      .where(eq(orderItems.orderId, orderId));

    // Group valid inventory items by product
    const inventoryByProduct = new Map<string, InventoryItemRequest[]>();
    for (const item of validInventoryItems) {
      if (!inventoryByProduct.has(item.productId)) {
        inventoryByProduct.set(item.productId, []);
      }
      inventoryByProduct.get(item.productId)!.push(item);
    }

    // Process fulfillment
    const result = await db.transaction(async (tx) => {
      const fulfilledItems: Array<{
        productName: string;
        newlyFulfilled: number;
        remainingNeeded: number;
        extraAdded: number;
      }> = [];
      let allFulfilled = true;

      for (const orderItem of orderItemsData) {
        const currentlyDelivered = (orderItem.deliveredInventoryIds || []).length;
        const stillNeeded = orderItem.quantity - currentlyDelivered;
        const itemsToAdd = inventoryByProduct.get(orderItem.productId) || [];

        const toFulfillCount = Math.min(stillNeeded, itemsToAdd.length);
        const extraCount = Math.max(0, itemsToAdd.length - toFulfillCount);

        // Create inventory items needed for order (mark as sold)
        const newSoldIds: string[] = [];
        for (let i = 0; i < toFulfillCount; i++) {
          const itemRequest = itemsToAdd[i];

          const [inserted] = await tx
            .insert(inventoryItems)
            .values({
              productId: orderItem.productId,
              templateId: orderItem.inventoryTemplateId!,
              values: itemRequest.values || {},
              status: "sold",
              purchasedAt: new Date(),
              orderItemId: orderItem.id,
            })
            .returning();

          newSoldIds.push(inserted.id);
        }

        // Update product stats for sold items (increase totalSold only, not stockCount)
        if (toFulfillCount > 0) {
          await tx
            .update(products)
            .set({
              totalSold: sql`${products.totalSold} + ${toFulfillCount}`,
              updatedAt: new Date(),
            })
            .where(eq(products.id, orderItem.productId));
        }

        // Create extra items as available for future sales
        for (let i = toFulfillCount; i < itemsToAdd.length; i++) {
          const itemRequest = itemsToAdd[i];

          const [inserted] = await tx
            .insert(inventoryItems)
            .values({
              productId: orderItem.productId,
              templateId: orderItem.inventoryTemplateId!,
              values: itemRequest.values || {},
              status: "available",
            })
            .returning();
        }

        // Update product stats for extra items (increase stockCount)
        if (extraCount > 0) {
          await tx
            .update(products)
            .set({
              stockCount: sql`${products.stockCount} + ${extraCount}`,
              updatedAt: new Date(),
            })
            .where(eq(products.id, orderItem.productId));
        }

        // Update order item with new inventory IDs
        const updatedIds = [...(orderItem.deliveredInventoryIds || []), ...newSoldIds];
        await tx
          .update(orderItems)
          .set({
            deliveredInventoryIds: sql`${JSON.stringify(updatedIds)}::jsonb`,
          })
          .where(eq(orderItems.id, orderItem.id));

        const remainingAfterAdd = stillNeeded - toFulfillCount;
        if (remainingAfterAdd > 0) {
          allFulfilled = false;
        }

        fulfilledItems.push({
          productName: orderItem.productName,
          newlyFulfilled: toFulfillCount,
          remainingNeeded: remainingAfterAdd,
          extraAdded: extraCount,
        });
      }

      // Update order status if all items fulfilled
      let updatedOrder = order;
      if (allFulfilled) {
        [updatedOrder] = await tx
          .update(orders)
          .set({
            status: "completed",
            fulfillmentStatus: "delivered",
            deliveredAt: new Date(),
            claimedBy: null,
            claimedAt: null,
            claimExpiresAt: null,
            updatedAt: new Date(),
          })
          .where(eq(orders.id, orderId))
          .returning();

        // Update delivery snapshot
        const deliveryData = await getOrderDeliveryData(orderId);
        await tx.execute(
          sql`
            UPDATE order_delivery_snapshots
            SET payload = ${JSON.stringify(deliveryData)}::jsonb
            WHERE order_id = ${orderId}
          `
        );
      }

      return {
        order: updatedOrder,
        fulfilledItems,
        allFulfilled,
      };
    });

    // Log activity
    await logActivity({
      userId: user.id,
      action: result.allFulfilled ? "order_completed" : "order_claimed",
      entity: "order",
      entityId: orderId,
      metadata: {
        itemsFulfilled: result.fulfilledItems,
      },
    });

    return NextResponse.json({
      success: true,
      data: {
        order: result.order,
        fulfilledItems: result.fulfilledItems,
        allFulfilled: result.allFulfilled,
        message: result.allFulfilled
          ? "Order fully fulfilled and completed"
          : "Order partially fulfilled, still needs more inventory",
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Fulfill pending order error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Individual Order API Routes
 *
 * GET /api/orders/[id] - Get order by ID
 * PUT /api/orders/[id] - Update order status
 * DELETE /api/orders/[id] - Cancel/delete order
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { orders, orderItems, products, couponUsage, coupons, users } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql } from "drizzle-orm";
import { fulfillOrder, getOrderDeliveryData } from "@/services/autoDelivery";
import { logOrderCancelled } from "@/services/activityLog";

type RouteContext = {
  params: Promise<{ id: string }>;
};

// ============================================================================
// GET /api/orders/[id] - Get order details
// ============================================================================()

export async function GET(
  request: NextRequest,
  context: RouteContext
) {
  try {
    const user = await requirePermission(PERMISSIONS.VIEW_ORDERS);
    const { id } = await context.params;

    const db = getDb();

    const [order] = await db
      .select({
        id: orders.id,
        customerEmail: orders.customerEmail,
        customerName: orders.customerName,
        subtotal: orders.subtotal,
        discount: orders.discount,
        total: orders.total,
        currency: orders.currency,
        couponId: orders.couponId,
        status: orders.status,
        fulfillmentStatus: orders.fulfillmentStatus,
        deliveredAt: orders.deliveredAt,
        processedBy: orders.processedBy,
        claimedBy: orders.claimedBy,
        claimedAt: orders.claimedAt,
        claimExpiresAt: orders.claimExpiresAt,
        createdAt: orders.createdAt,
        updatedAt: orders.updatedAt,
      })
      .from(orders)
      .where(and(eq(orders.id, id), sql`deleted_at IS NULL`))
      .limit(1);

    if (!order) {
      return NextResponse.json(
        { success: false, error: "Order not found" },
        { status: 404 }
      );
    }

    // Get claimant name if claimed
    let claimantName = null;
    if (order.claimedBy) {
      const [claimant] = await db
        .select({ name: users.name })
        .from(users)
        .where(eq(users.id, order.claimedBy))
        .limit(1);
      claimantName = claimant?.name || null;
    }

    // Get order items
    const items = await db
      .select({
        id: orderItems.id,
        productId: orderItems.productId,
        quantity: orderItems.quantity,
        unitPrice: orderItems.price,
        subtotal: orderItems.subtotal,
        deliveredInventoryIds: orderItems.deliveredInventoryIds,
        productName: products.name,
        productSlug: products.slug,
      })
      .from(orderItems)
      .innerJoin(products, eq(orderItems.productId, products.id))
      .where(eq(orderItems.orderId, id));

    // Get delivery data if fulfilled
    let deliveryData = null;
    if (order.fulfillmentStatus === "delivered") {
      deliveryData = await getOrderDeliveryData(id);
    }

    return NextResponse.json({
      success: true,
      data: {
        ...order,
        claimantName,
        isClaimedByMe: order.claimedBy === user.id,
        isClaimExpired: order.claimExpiresAt ? order.claimExpiresAt < new Date() : false,
        items,
        deliveryData,
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Get order error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ============================================================================
// PUT /api/orders/[id] - Update order (process, complete, cancel)
// ============================================================================()

export async function PUT(
  request: NextRequest,
  context: RouteContext
) {
  try {
    const user = await requirePermission(PERMISSIONS.PROCESS_ORDERS);
    const { id } = await context.params;
    const isAdmin = user.role === "admin";

    const body = await request.json();
    const { action, status, fulfillmentStatus } = body;

    const db = getDb();

    // Get current order with claim info
    const [order] = await db
      .select({
        id: orders.id,
        status: orders.status,
        fulfillmentStatus: orders.fulfillmentStatus,
        claimedBy: orders.claimedBy,
        claimedAt: orders.claimedAt,
        claimExpiresAt: orders.claimExpiresAt,
      })
      .from(orders)
      .where(and(eq(orders.id, id), sql`deleted_at IS NULL`))
      .limit(1);

    if (!order) {
      return NextResponse.json(
        { success: false, error: "Order not found" },
        { status: 404 }
      );
    }

    // Check claim enforcement
    const isClaimExpired = order.claimExpiresAt && order.claimExpiresAt < new Date();
    const isClaimedByMe = order.claimedBy === user.id;
    const isClaimedByOther = order.claimedBy && !isClaimedByMe && !isClaimExpired;

    // Non-admin staff can only modify orders they've claimed (or unclaimed orders)
    if (!isAdmin && isClaimedByOther) {
      return NextResponse.json(
        { success: false, error: "This order is claimed by another staff member" },
        { status: 403 }
      );
    }

    // Auto-claim if not claimed and user is working on it
    if (!order.claimedBy && !isAdmin) {
      const CLAIM_TTL_MINUTES = 30;
      const claimExpiresAt = new Date(Date.now() + CLAIM_TTL_MINUTES * 60 * 1000);
      await db
        .update(orders)
        .set({
          claimedBy: user.id,
          claimedAt: new Date(),
          claimExpiresAt,
          updatedAt: new Date(),
        })
        .where(eq(orders.id, id));
    }

    // Handle different actions
    switch (action) {
      case "fulfill": {
        // Trigger auto-delivery
        const result = await fulfillOrder(id, user.id);

        if (result.success) {
          return NextResponse.json({
            success: true,
            data: {
              message: "Order fulfilled successfully",
              fulfillmentStatus: result.fulfillmentStatus,
              deliveredItems: result.deliveredItems,
              errors: result.errors,
            },
          });
        } else {
          return NextResponse.json(
            {
              success: false,
              error: "Fulfillment failed",
              details: result.errors,
            },
            { status: 400 }
          );
        }
      }

      case "complete": {
        // Mark order as completed (without auto-delivery)
        const [updated] = await db
          .update(orders)
          .set({
            status: "completed",
            fulfillmentStatus: "delivered",
            deliveredAt: new Date(),
            processedBy: user.id,
            updatedAt: new Date(),
          })
          .where(eq(orders.id, id))
          .returning();

        return NextResponse.json({
          success: true,
          data: updated,
        });
      }

      case "cancel": {
        const { reason } = body;

        const [updated] = await db
          .update(orders)
          .set({
            status: "cancelled",
            fulfillmentStatus: "failed",
            processedBy: user.id,
            updatedAt: new Date(),
          })
          .where(eq(orders.id, id))
          .returning();

        // Log cancellation
        await logOrderCancelled(user.id, id, reason);

        return NextResponse.json({
          success: true,
          data: updated,
        });
      }

      case "update_status": {
        // Generic status update
        const updateData: any = { updatedAt: new Date() };
        if (status && ["pending", "completed", "cancelled", "refunded"].includes(status)) {
          updateData.status = status;
        }
        if (fulfillmentStatus && ["pending", "processing", "delivered", "failed"].includes(fulfillmentStatus)) {
          updateData.fulfillmentStatus = fulfillmentStatus;
          if (fulfillmentStatus === "delivered") {
            updateData.deliveredAt = new Date();
          }
        }

        const [updated] = await db
          .update(orders)
          .set(updateData)
          .where(eq(orders.id, id))
          .returning();

        return NextResponse.json({
          success: true,
          data: updated,
        });
      }

      default:
        return NextResponse.json(
          { success: false, error: "Invalid action. Use: fulfill, complete, cancel, or update_status" },
          { status: 400 }
        );
    }
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Update order error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ============================================================================
// DELETE /api/orders/[id] - Soft delete order
// ============================================================================()

export async function DELETE(
  request: NextRequest,
  context: RouteContext
) {
  try {
    const user = await requirePermission(PERMISSIONS.PROCESS_ORDERS);
    const { id } = await context.params;
    const isAdmin = user.role === "admin";

    const db = getDb();

    const [existing] = await db
      .select({
        id: orders.id,
        claimedBy: orders.claimedBy,
        claimExpiresAt: orders.claimExpiresAt,
      })
      .from(orders)
      .where(and(eq(orders.id, id), sql`deleted_at IS NULL`))
      .limit(1);

    if (!existing) {
      return NextResponse.json(
        { success: false, error: "Order not found" },
        { status: 404 }
      );
    }

    // Check claim enforcement
    const isClaimExpired = existing.claimExpiresAt && existing.claimExpiresAt < new Date();
    const isClaimedByMe = existing.claimedBy === user.id;
    const isClaimedByOther = existing.claimedBy && !isClaimedByMe && !isClaimExpired;

    // Non-admin staff can only delete orders they've claimed (or unclaimed orders)
    if (!isAdmin && isClaimedByOther) {
      return NextResponse.json(
        { success: false, error: "This order is claimed by another staff member" },
        { status: 403 }
      );
    }

    // Soft delete
    await db
      .update(orders)
      .set({
        deletedAt: new Date(),
        status: "cancelled",
        updatedAt: new Date(),
      })
      .where(eq(orders.id, id));

    return NextResponse.json({
      success: true,
      data: { message: "Order deleted successfully" },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Delete order error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Order Claiming API Routes
 *
 * POST /api/orders/claim - Claim an order or next pending order
 * POST /api/orders/release - Release a claimed order
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { orders, users } from "@/db/schema";
import { requirePermission } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, or, isNull } from "drizzle-orm";
import { logActivity } from "@/services/activityLog";

// Helper to check if user can modify the order
async function canModifyOrder(orderId: string, userId: string, isAdmin: boolean): Promise<{ canModify: boolean; error?: string }> {
  const db = getDb();

  const [order] = await db
    .select({
      claimedBy: orders.claimedBy,
      claimedAt: orders.claimedAt,
      claimExpiresAt: orders.claimExpiresAt,
    })
    .from(orders)
    .where(eq(orders.id, orderId))
    .limit(1);

  if (!order) {
    return { canModify: false, error: "Order not found" };
  }

  // Admins can always modify
  if (isAdmin) {
    return { canModify: true };
  }

  // Check if claimed by someone else
  if (order.claimedBy && order.claimedBy !== userId) {
    // Check if claim expired
    if (order.claimExpiresAt && order.claimExpiresAt > new Date()) {
      return { canModify: false, error: "Order is claimed by another staff member" };
    }
  }

  return { canModify: true };
}

// ============================================================================
// POST /api/orders/claim - Claim an order
// ============================================================================

export async function POST(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.PROCESS_ORDERS);
    const isAdmin = user.role === "admin";

    const body = await request.json();
    const { orderId, claimNext } = body;

    const db = getDb();

    if (claimNext) {
      // Claim the next pending order
      const CLAIM_TTL_MINUTES = 30; // Auto-release after 30 minutes
      const claimExpiresAt = new Date(Date.now() + CLAIM_TTL_MINUTES * 60 * 1000);

      // Use FOR UPDATE SKIP LOCKED to safely get next pending order
      const result = await db.transaction(async (tx) => {
        const orderResult = await tx.execute(
          sql`
            UPDATE orders
            SET claimed_by = ${user.id},
                claimed_at = NOW(),
                claim_expires_at = ${claimExpiresAt},
                updated_at = NOW()
            WHERE id = (
              SELECT id
              FROM orders
              WHERE (claimed_by IS NULL
                     OR claim_expires_at < NOW())
                AND status = 'pending'
                AND deleted_at IS NULL
              ORDER BY created_at ASC
              LIMIT 1
              FOR UPDATE SKIP LOCKED
            )
            RETURNING id, customer_email, customer_name, total, created_at
          `
        );

        if (!orderResult.rows || orderResult.rows.length === 0) {
          return null;
        }

        const claimedOrder = orderResult.rows[0] as any;

        // Log activity
        await logActivity({
          userId: user.id,
          action: "order_claimed",
          entity: "order",
          entityId: claimedOrder.id,
          metadata: { autoClaimed: true },
        });

        return claimedOrder;
      });

      if (!result) {
        return NextResponse.json(
          { success: false, error: "No pending orders available to claim" },
          { status: 404 }
        );
      }

      return NextResponse.json({
        success: true,
        data: {
          order: result,
          claimedBy: user.id,
          claimedAt: new Date(),
          claimExpiresAt: new Date(Date.now() + 30 * 60 * 1000),
        },
      });
    }

    // Claim specific order
    if (!orderId) {
      return NextResponse.json(
        { success: false, error: "Order ID is required when not claiming next" },
        { status: 400 }
      );
    }

    // Check if order exists
    const [order] = await db
      .select()
      .from(orders)
      .where(
        and(
          eq(orders.id, orderId),
          sql`${orders.deletedAt} IS NULL`
        )
      )
      .limit(1);

    if (!order) {
      return NextResponse.json(
        { success: false, error: "Order not found" },
        { status: 404 }
      );
    }

    // Check if already claimed by someone else
    if (order.claimedBy && order.claimedBy !== user.id) {
      if (order.claimExpiresAt && order.claimExpiresAt > new Date()) {
        // Get claimant name
        const [claimant] = await db
          .select({ name: users.name })
          .from(users)
          .where(eq(users.id, order.claimedBy))
          .limit(1);

        return NextResponse.json(
          {
            success: false,
            error: "Order is already claimed",
            claimedBy: order.claimedBy,
            claimantName: claimant?.name,
            claimedAt: order.claimedAt,
          },
          { status: 409 }
        );
      }
      // Claim expired, allow re-claiming
    }

    // Set TTL for claim (30 minutes)
    const CLAIM_TTL_MINUTES = 30;
    const claimExpiresAt = new Date(Date.now() + CLAIM_TTL_MINUTES * 60 * 1000);

    // Update order with claim
    const [updated] = await db
      .update(orders)
      .set({
        claimedBy: user.id,
        claimedAt: new Date(),
        claimExpiresAt,
        updatedAt: new Date(),
      })
      .where(eq(orders.id, orderId))
      .returning();

    // Log activity
    await logActivity({
      userId: user.id,
      action: "order_claimed",
      entity: "order",
      entityId: orderId,
      metadata: { previousClaimant: order.claimedBy },
    });

    return NextResponse.json({
      success: true,
      data: updated,
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Claim order error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Orders API Routes
 *
 * GET /api/orders - List orders with filtering and pagination
 * POST /api/orders - Create a new order
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { orders, orderItems, products, coupons, users } from "@/db/schema";
import { requirePermission, getCurrentUser } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, and, sql, desc, like, or, inArray, isNull } from "drizzle-orm";
import { fulfillOrder } from "@/services/autoDelivery";

// ============================================================================
// GET /api/orders - List orders
// ============================================================================()

export async function GET(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.VIEW_ORDERS);
    const isAdmin = user.role === "admin";

    const { searchParams } = new URL(request.url);
    const search = searchParams.get("search");
    const status = searchParams.get("status");
    const fulfillmentStatus = searchParams.get("fulfillmentStatus");
    const claimStatus = searchParams.get("claimStatus"); // 'unclaimed', 'mine', 'others', 'any'
    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "20");
    const offset = (page - 1) * limit;

    const db = getDb();

    // Build conditions
    const conditions = [sql`orders.deleted_at IS NULL`];

    if (search) {
      conditions.push(
        or(
          like(orders.customerEmail, `%${search}%`),
          like(orders.customerName || "", `%${search}%`)
        )!
      );
    }

    if (status) {
      conditions.push(eq(orders.status, status as "pending" | "completed" | "cancelled" | "refunded"));
    }

    if (fulfillmentStatus) {
      conditions.push(eq(orders.fulfillmentStatus, fulfillmentStatus as "pending" | "processing" | "delivered" | "failed"));
    }

    // Claim filtering
    if (claimStatus) {
      switch (claimStatus) {
        case "unclaimed":
          conditions.push(or(isNull(orders.claimedBy), sql`claim_expires_at < NOW()`)!);
          break;
        case "mine":
          conditions.push(eq(orders.claimedBy, user.id));
          break;
        case "others":
          conditions.push(and(
            sql`${orders.claimedBy} != ${user.id}`,
            sql`claim_expires_at >= NOW()`
          )!);
          break;
        // 'any' - no filter needed
      }
    }

    // Get total count
    const countResult = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(orders)
      .where(and(...conditions));

    const total = countResult[0]?.count || 0;

    // Get orders with claim info
    const ordersList = await db
      .select({
        id: orders.id,
        customerEmail: orders.customerEmail,
        customerName: orders.customerName,
        subtotal: orders.subtotal,
        discount: orders.discount,
        total: orders.total,
        currency: orders.currency,
        couponId: orders.couponId,
        status: orders.status,
        fulfillmentStatus: orders.fulfillmentStatus,
        deliveredAt: orders.deliveredAt,
        processedBy: orders.processedBy,
        claimedBy: orders.claimedBy,
        claimedAt: orders.claimedAt,
        claimExpiresAt: orders.claimExpiresAt,
        claimantName: users.name,
        createdAt: orders.createdAt,
        updatedAt: orders.updatedAt,
      })
      .from(orders)
      .leftJoin(users, eq(orders.claimedBy, users.id))
      .where(and(...conditions))
      .orderBy(desc(orders.createdAt))
      .limit(limit)
      .offset(offset);

    // Get order items for each order
    const orderIds = ordersList.map((o) => o.id);

    const itemsList = await db
      .select({
        id: orderItems.id,
        orderId: orderItems.orderId,
        productId: orderItems.productId,
        quantity: orderItems.quantity,
        unitPrice: orderItems.price,
        subtotal: orderItems.subtotal,
        productName: products.name,
        productSlug: products.slug,
      })
      .from(orderItems)
      .innerJoin(products, eq(orderItems.productId, products.id))
      .where(inArray(orderItems.orderId, orderIds));

    // Group items by order and add computed fields
    const ordersWithItems = ordersList.map((order: any) => ({
      ...order,
      isClaimedByMe: order.claimedBy === user.id,
      isClaimExpired: order.claimExpiresAt ? order.claimExpiresAt < new Date() : false,
      items: itemsList.filter((item) => item.orderId === order.id),
    }));

    return NextResponse.json({
      success: true,
      data: ordersWithItems,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Get orders error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ============================================================================
// POST /api/orders - Create new order (public endpoint for checkout)
// ============================================================================()

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const {
      customerEmail,
      customerName,
      items,
      couponCode,
      currency = "USD",
    } = body;

    // Validate input
    if (!customerEmail || !Array.isArray(items) || items.length === 0) {
      return NextResponse.json(
        { success: false, error: "Email and items are required" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Verify products exist and get prices
    const productIds = items.map((i: { productId: string }) => i.productId);
    const productsData = await db
      .select({
        id: products.id,
        name: products.name,
        price: products.basePrice,
        isActive: products.isActive,
      })
      .from(products)
      .where(inArray(products.id, productIds));

    if (productsData.length !== productIds.length) {
      return NextResponse.json(
        { success: false, error: "One or more products not found" },
        { status: 404 }
      );
    }

    // Check all products are active
    const inactiveProducts = productsData.filter((p) => !p.isActive);
    if (inactiveProducts.length > 0) {
      return NextResponse.json(
        { success: false, error: "One or more products are not available" },
        { status: 400 }
      );
    }

    // Calculate subtotal
    let subtotal = 0;
    const orderItemsData = items.map((item: { productId: string; quantity: number }) => {
      const product = productsData.find((p) => p.id === item.productId);
      const unitPrice = parseFloat(product!.price);
      const itemSubtotal = unitPrice * item.quantity;
      subtotal += itemSubtotal;

      return {
        productId: item.productId,
        quantity: item.quantity,
        unitPrice: unitPrice.toString(),
        subtotal: itemSubtotal.toString(),
      };
    });

    // Apply coupon if provided
    let discount = 0;
    let couponId: string | null = null;

    if (couponCode) {
      const [coupon] = await db
        .select()
        .from(coupons)
        .where(
          and(
            eq(coupons.code, couponCode.toUpperCase()),
            sql`is_active = true`,
            sql`deleted_at IS NULL`,
            sql`(valid_until IS NULL OR valid_until > NOW())`
          )
        )
        .limit(1);

      if (coupon) {
        // Check usage limits
        if (coupon.usageLimit && coupon.usageCount >= coupon.usageLimit) {
          return NextResponse.json(
            { success: false, error: "Coupon has reached its usage limit" },
            { status: 400 }
          );
        }

        // Check min purchase
        const minPurchase = parseFloat(coupon.minPurchase || "0");
        if (subtotal < minPurchase) {
          return NextResponse.json(
            {
              success: false,
              error: `Minimum purchase of $${minPurchase} required for this coupon`,
            },
            { status: 400 }
          );
        }

        // Calculate discount
        if (coupon.discountType === "percentage") {
          discount = subtotal * (parseFloat(coupon.discountValue) / 100);
          if (coupon.maxDiscount) {
            discount = Math.min(discount, parseFloat(coupon.maxDiscount));
          }
        } else {
          discount = parseFloat(coupon.discountValue);
        }

        couponId = coupon.id;
      }
    }

    const total = subtotal - discount;

    // Create order
    const [order] = await db
      .insert(orders)
      .values({
        customerEmail,
        customerName: customerName || null,
        subtotal: subtotal.toString(),
        discount: discount.toString(),
        total: total.toString(),
        currency,
        couponId,
        status: "pending",
        fulfillmentStatus: "pending",
      })
      .returning();

    // Create order items
    await db.insert(orderItems).values(
      orderItemsData.map((item) => ({
        orderId: order.id,
        ...item,
      }))
    );

    return NextResponse.json({
      success: true,
      data: {
        order,
        items: orderItemsData,
      },
    }, { status: 201 });
  } catch (error) {
    console.error("Create order error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

