    // Build conditions
    const conditions = [sql`${platforms.deletedAt} IS NULL`];

    if (search) {
      conditions.push(like(platforms.name, `%${search}%`));
    }

    if (isActive !== null && isActive !== "") {
      conditions.push(eq(platforms.isActive, isActive === "true"));
    }

    // Get all platforms
    const allPlatforms = await db
      .select()
      .from(platforms)
      .where(and(...conditions))
      .orderBy(platforms.sortOrder, platforms.name);

    if (asTree) {
      // Build tree structure
      const platformMap = new Map<string, any>();
      const rootPlatforms: any[] = [];

      // First pass: create map and initialize children arrays
      for (const platform of allPlatforms) {
        platformMap.set(platform.id, {
          ...platform,
          children: [],
        });
      }

      // Second pass: build hierarchy
      for (const platform of allPlatforms) {
        const node = platformMap.get(platform.id)!;
        if (platform.parentId) {
          const parent = platformMap.get(platform.parentId);
          if (parent) {
            parent.children.push(node);
          } else {
            // Parent not found (might be deleted), treat as root
            rootPlatforms.push(node);
          }
        } else {
          rootPlatforms.push(node);
        }
      }

      return NextResponse.json({
        success: true,
        data: rootPlatforms,
      });
    }

    // Return flat list
    return NextResponse.json({
      success: true,
      data: allPlatforms,
    });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Get platforms error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ============================================================================
// POST /api/platforms - Create platform
// ============================================================================

export async function POST(request: NextRequest) {
  try {
    const user = await requirePermission(PERMISSIONS.MANAGE_PRODUCTS);

    const body = await request.json();
    const { name, parentId, sortOrder } = body;

    // Validate input
    if (!name || name.trim().length === 0) {
      return NextResponse.json(
        { success: false, error: "Name is required" },
        { status: 400 }
      );
    }

    if (name.length > 100) {
      return NextResponse.json(
        { success: false, error: "Name must be 100 characters or less" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Validate parentId if provided
    if (parentId) {
      const [parent] = await db
        .select()
        .from(platforms)
        .where(
          and(
            eq(platforms.id, parentId),
            sql`${platforms.deletedAt} IS NULL`
          )
        )
        .limit(1);

      if (!parent) {
        return NextResponse.json(
          { success: false, error: "Parent platform not found" },
          { status: 404 }
        );
      }

      // Check for duplicate name under same parent
      const [existing] = await db
        .select()
        .from(platforms)
        .where(
          and(
            eq(platforms.name, name.trim()),
            eq(platforms.parentId, parentId),
            sql`${platforms.deletedAt} IS NULL`
          )
        )
        .limit(1);

      if (existing) {
        return NextResponse.json(
          { success: false, error: "Platform with this name already exists under this parent" },
          { status: 409 }
        );
      }
    } else {
      // Check for duplicate root-level name
      const [existing] = await db
        .select()
        .from(platforms)
        .where(
          and(
            eq(platforms.name, name.trim()),
            isNull(platforms.parentId),
            sql`${platforms.deletedAt} IS NULL`
          )
        )
        .limit(1);

      if (existing) {
        return NextResponse.json(
          { success: false, error: "Platform with this name already exists at root level" },
          { status: 409 }
        );
      }
    }

    // Create platform
    const newPlatforms = await db
      .insert(platforms)
      .values({
        name: name.trim(),
        parentId: parentId || null,
        sortOrder: sortOrder || 0,
        isActive: true,
      })
      .returning();

    const newPlatform = (newPlatforms as any[])[0];

    // Log activity
    await logActivity({
      userId: user.id,
      action: "platform_created",
      entity: "platform",
      entityId: newPlatform.id,
      metadata: { name: newPlatform.name, parentId: newPlatform.parentId },
    });

    return NextResponse.json({
      success: true,
      data: newPlatform,
    }, { status: 201 });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Create platform error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * Products API Routes
 *
 * GET /api/products - List all products (with filtering, pagination)
 * POST /api/products - Create a new product (admin/staff only)
 */

import { NextRequest, NextResponse } from "next/server";
import { getDb } from "@/db";
import { products, productPlatforms, productImages, platforms, inventoryTemplates } from "@/db/schema";
import { requirePermission, getCurrentUser } from "@/lib/auth";
import { PERMISSIONS } from "@/types";
import { eq, like, or, desc, sql, and, inArray } from "drizzle-orm";
import { logProductCreated } from "@/services/activityLog";

// ============================================================================
// GET /api/products - List products
// ============================================================================()

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const search = searchParams.get("search");
    const isActive = searchParams.get("isActive");
    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "20");
    const offset = (page - 1) * limit;

    const db = getDb();

    // Build query conditions
    const conditions = [sql`products.deleted_at IS NULL`];

    if (search) {
      conditions.push(
        or(
          like(products.name, `%${search}%`),
          like(products.description || "", `%${search}%`)
        )!
      );
    }

    if (isActive !== null && isActive !== "") {
      conditions.push(eq(products.isActive, isActive === "true"));
    }

    // Get total count
    const countResult = await db
      .select({ count: sql<number>`count(*)::int` })
      .from(products)
      .where(conditions.length > 0 ? and(...conditions) : undefined);

    const total = countResult[0]?.count || 0;

    // Get products with related data
    const productsList = await db
      .select({
        id: products.id,
        name: products.name,
        slug: products.slug,
        description: products.description,
        price: products.basePrice,
        inventoryTemplateId: products.inventoryTemplateId,
        isActive: products.isActive,
        stockCount: products.stockCount,
        totalSold: products.totalSold,
        averageRating: products.averageRating,
        reviewCount: products.reviewCount,
        createdAt: products.createdAt,
        updatedAt: products.updatedAt,
        templateName: inventoryTemplates.name,
      })
      .from(products)
      .leftJoin(inventoryTemplates, eq(products.inventoryTemplateId, inventoryTemplates.id))
      .where(conditions.length > 0 ? and(...conditions) : undefined)
      .orderBy(desc(products.createdAt))
      .limit(limit)
      .offset(offset);

    // Get platforms and images for each product
    const productIds = productsList.map((p) => p.id);

    // Only query related data if we have products
    let platformLinksList: Array<{
      id: string;
      productId: string;
      platformId: string;
      platformName: string;
      platformParentId: string | null;
    }> = [];
    let imagesList: typeof productImages.$inferSelect[] = [];

    if (productIds.length > 0) {
      [platformLinksList, imagesList] = await Promise.all([
        db
          .select({
            id: productPlatforms.id,
            productId: productPlatforms.productId,
            platformId: productPlatforms.platformId,
            platformName: platforms.name,
            platformParentId: platforms.parentId,
          })
          .from(productPlatforms)
          .innerJoin(platforms, eq(productPlatforms.platformId, platforms.id))
          .where(inArray(productPlatforms.productId, productIds)),
        db
          .select()
          .from(productImages)
          .where(inArray(productImages.productId, productIds))
          .orderBy(productImages.sortOrder),
      ]);
    }

    // Group related data
    const productsWithRelations = productsList.map((product) => ({
      ...product,
      platforms: platformLinksList
        .filter((p) => p.productId === product.id)
        .map((p) => ({
          id: p.platformId,
          name: p.platformName,
          parentId: p.platformParentId,
        })),
      images: imagesList.filter((i) => i.productId === product.id),
    }));

    return NextResponse.json({
      success: true,
      data: productsWithRelations,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    console.error("Get products error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

// ============================================================================
// POST /api/products - Create product
// ============================================================================()

export async function POST(request: NextRequest) {
  try {
    // Check permissions
    const user = await requirePermission(PERMISSIONS.MANAGE_PRODUCTS);

    const body = await request.json();
    const {
      name,
      slug,
      description,
      price,
      inventoryTemplateId,
      platformIds = [],
      images = [],
    } = body;

    // Validate input
    if (!name || !slug || !price) {
      return NextResponse.json(
        { success: false, error: "Name, slug, and price are required" },
        { status: 400 }
      );
    }

    const db = getDb();

    // Check if slug is unique
    const existing = await db
      .select()
      .from(products)
      .where(eq(products.slug, slug))
      .limit(1);

    if (existing.length > 0) {
      return NextResponse.json(
        { success: false, error: "Product with this slug already exists" },
        { status: 409 }
      );
    }

    // Validate platformIds if provided
    if (platformIds.length > 0) {
      const platformCount = await db
        .select({ count: sql<number>`count(*)::int` })
        .from(platforms)
        .where(
          and(
            inArray(platforms.id, platformIds),
            sql`${platforms.deletedAt} IS NULL`,
            eq(platforms.isActive, true)
          )
        );

      if (platformCount[0]?.count !== platformIds.length) {
        return NextResponse.json(
          { success: false, error: "One or more platforms are invalid or inactive" },
          { status: 400 }
        );
      }
    }

    // Create product
    const [newProduct] = await db
      .insert(products)
      .values({
        name,
        slug,
        description,
        price: price.toString(),
        inventoryTemplateId,
        isActive: true,
        stockCount: 0,
        totalSold: 0,
      })
      .returning();

    // Add platform links if provided
    if (platformIds.length > 0) {
      await db.insert(productPlatforms).values(
        platformIds.map((platformId: string) => ({
          productId: newProduct.id,
          platformId,
        }))
      );
    }

    // Add images if provided
    if (images.length > 0) {
      await db.insert(productImages).values(
        images.map((img: { url: string; alt?: string; order?: number }, index: number) => ({
          productId: newProduct.id,
          url: img.url,
          alt: img.alt || null,
          order: img.order ?? index,
        }))
      );
    }

    // Log activity
    await logProductCreated(user.id, newProduct.id, name);

    return NextResponse.json({
      success: true,
      data: newProduct,
    }, { status: 201 });
  } catch (error) {
    if (error instanceof Error) {
      if (error.message === "UNAUTHORIZED") {
        return NextResponse.json(
          { success: false, error: "Authentication required" },
          { status: 401 }
        );
      }
      if (error.message === "FORBIDDEN") {
        return NextResponse.json(
          { success: false, error: "Insufficient permissions" },
          { status: 403 }
        );
      }
    }

    console.error("Create product error:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error" },
      { status: 500 }
    );
  }
}

