                  {templateFields.length > 0 && (
                    <div className="px-4 py-2 bg-slate-900/30 border-b border-slate-700 flex flex-wrap gap-3 text-xs">
                      {templateFields.map((f) => (
                        <span key={f.name} className="text-slate-400">
