            fetchInventory();
            fetchProducts();
          }}
        />
      )}
    </div>
  );
}

// Add Inventory Modal Component with template fields
function AddInventoryModal({
  productId,
  productName,
  templateFields,
  onClose,
  onSuccess,
}: {
  productId: string;
  productName: string;
  templateFields: TemplateField[];
  onClose: () => void;
  onSuccess: () => void;
}) {
  const [items, setItems] = useState("");
  const [batchName, setBatchName] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [pendingData, setPendingData] = useState<{ pendingItems: number; pendingOrdersCount: number } | null>(null);
  const [sellPendingFirst, setSellPendingFirst] = useState(false);

  // Fetch pending items count on mount
  useEffect(() => {
    const fetchPendingCount = async () => {
      try {
        const res = await fetch(`/api/inventory/pending-count?productId=${productId}`);
        const data = await res.json();
        if (data.success && data.data.pendingItems > 0) {
          setPendingData(data.data);
        }
      } catch (err) {
        console.error("Failed to fetch pending count");
      }
    };
    fetchPendingCount();
  }, [productId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!items.trim()) {
      alert("Please enter inventory items");
      return;
    }

    // Parse items (one per line, comma-separated values)
    const lines = items.trim().split("\n");
    const parsedItems = lines
      .map((line) => line.trim())
      .filter((line) => line)
      .map((line) => {
        const values = line.split(",").map((v) => v.trim());
        // Build object based on template fields
        const itemObj: Record<string, string> = {};
        templateFields.forEach((field, index) => {
          itemObj[field.name] = values[index] || "";
        });
        return itemObj;
      });

    if (parsedItems.length === 0) {
      alert("No valid items to add");
      return;
    }

    setSubmitting(true);
    try {
      const res = await fetch("/api/inventory", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productId,
          items: parsedItems,
          batchName: batchName || undefined,
        }),
      });

      const data = await res.json();

      if (data.success) {
        onSuccess();
      } else {
        alert(data.error || "Failed to add inventory");
      }
    } catch (err) {
      alert("Failed to add inventory");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <div className="bg-slate-800 rounded-lg border border-slate-700 w-full max-w-lg p-6">
        <h2 className="text-xl font-bold text-white mb-4">
          Add Inventory - {productName}
        </h2>

        {/* Pending items notice */}
        {pendingData && pendingData.pendingItems > 0 && (
          <div className="mb-4 p-3 bg-yellow-500/10 border border-yellow-500/30 rounded-lg">
            <div className="flex items-start gap-3">
              <svg className="w-5 h-5 text-yellow-400 mt-0.5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
              <div className="flex-1">
                <p className="text-yellow-200 text-sm font-medium">
                  You have {pendingData.pendingItems} pending item(s) in {pendingData.pendingOrdersCount} order(s)
                </p>
                <div className="mt-2">
                  <label className="flex items-center gap-2 text-sm text-yellow-200/80 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={sellPendingFirst}
                      onChange={(e) => setSellPendingFirst(e.target.checked)}
                      className="w-4 h-4 rounded border-yellow-500/30 bg-slate-900 text-yellow-400 focus:ring-yellow-500"
                    />
                    <span>Sell to pending orders first (new inventory will fulfill pending orders)</span>
                  </label>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Template info */}
        {templateFields.length > 0 && (
          <div className="mb-4 p-3 bg-slate-900/50 rounded border border-slate-700">
            <p className="text-sm text-slate-400 mb-2">Template fields:</p>
            <div className="flex flex-wrap gap-2 text-xs">
              {templateFields.map((f) => (
                <span key={f.name} className="px-2 py-1 bg-slate-700 rounded">
                  {f.name}
                  {f.required && <span className="text-red-400"> *</span>}
                </span>
              ))}
            </div>
            <p className="text-xs text-slate-500 mt-2">
              Enter values in order: {templateFields.map((f) => f.name).join(", ")}
            </p>
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <div className="mb-4">
            <label className="block text-sm font-medium text-slate-300 mb-1">
              Batch Name (optional)
            </label>
            <input
              type="text"
              value={batchName}
              onChange={(e) => setBatchName(e.target.value)}
              className="w-full px-3 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="e.g., Import 2024-03-15"
            />
          </div>

          <div className="mb-4">
            <label className="block text-sm font-medium text-slate-300 mb-1">
              Inventory Items *
            </label>
            <textarea
              value={items}
              onChange={(e) => setItems(e.target.value)}
              className="w-full px-3 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono text-sm"
              rows={10}
              placeholder={templateFields.length > 0
                ? `One item per line, comma-separated values\nExample: ${templateFields.map((f) => f.name).join(", ")}`
                : "One item per line, comma-separated values\nXXXXX-XXXXX-XXXXX, extra info"
              }
              required
            />
            <p className="text-xs text-slate-500 mt-1">
              {templateFields.length > 0
                ? `Values should be in order: ${templateFields.map((f) => f.name).join(", ")}`
                : "First value will be used as the key/code"
              }
            </p>
          </div>

          <div className="flex justify-end gap-3">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-slate-300 hover:text-white transition-colors"
              disabled={submitting}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={submitting}
              className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors disabled:opacity-50"
            >
              {submitting ? "Adding..." : `Add ${items.split("\n").filter(l => l.trim()).length} Items`}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

/**
 * Global Inventory Search Page
 *
 * Emergency search for inventory items across all products
 */

"use client";

import { useState } from "react";
import { InventorySearchResults } from "@/components/dashboard/InventorySearchResults";

export default function InventorySearchPage() {
  const [query, setQuery] = useState("");
  const [searching, setSearching] = useState(false);
  const [results, setResults] = useState<any[]>([]);
  const [statusFilter, setStatusFilter] = useState<string>("");

  const handleSearch = async () => {
    if (!query.trim()) return;

    setSearching(true);
    try {
      const params = new URLSearchParams({ q: query });
      if (statusFilter) params.append("status", statusFilter);

      const res = await fetch(`/api/inventory/search?${params}`);
      const data = await res.json();

      if (data.success) {
        setResults(data.data);
      } else {
        alert(data.error || "Search failed");
      }
    } catch (err) {
      alert("Search failed");
    } finally {
      setSearching(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      handleSearch();
    }
  };

  return (
    <div>
      {/* Header */}
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-white">Inventory Search</h1>
        <p className="text-slate-400 mt-1">
          Global search across all inventory items
        </p>
      </div>

      {/* Search Box */}
      <div className="bg-slate-800 rounded-lg border border-slate-700 p-6 mb-6">
        <div className="flex gap-4">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyPress={handleKeyPress}
            placeholder="Search by code, email, or any value..."
            className="flex-1 px-4 py-3 bg-slate-900 border border-slate-700 rounded-lg text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
            autoFocus
          />
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="px-4 py-3 bg-slate-900 border border-slate-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="">All Statuses</option>
            <option value="available">Available</option>
            <option value="reserved">Reserved</option>
            <option value="sold">Sold</option>
            <option value="expired">Expired</option>
          </select>
          <button
            onClick={handleSearch}
            disabled={searching || !query.trim()}
            className="px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {searching ? "Searching..." : "Search"}
          </button>
        </div>
      </div>

      {/* Results */}
      {results.length > 0 && (
        <InventorySearchResults results={results} query={query} />
      )}

      {/* Empty State */}
      {!searching && results.length === 0 && query === "" && (
        <div className="text-center py-16">
          <svg
            className="w-16 h-16 mx-auto text-slate-600 mb-4"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
            />
          </svg>
          <h3 className="text-lg font-medium text-white mb-2">
            Search Inventory
          </h3>
          <p className="text-slate-400">
            Enter a code, email, or any value to search across all inventory items
          </p>
        </div>
      )}

      {/* No Results */}
      {!searching && results.length === 0 && query !== "" && (
        <div className="text-center py-16">
          <p className="text-slate-400">No results found for "{query}"</p>
        </div>
      )}
    </div>
  );
}

"use client";

/**
 * Inventory Templates Management Page
 *
 * Create and manage inventory templates
 */

import { useState, useEffect } from "react";

interface FieldSchema {
  name: string;
  type: "string" | "number" | "boolean";
  required: boolean;
  label: string;
}

interface InventoryTemplate {
  id: string;
  name: string;
  description: string | null;
  fieldsSchema: FieldSchema[];
  isActive: boolean;
  createdAt: string;
}

export default function InventoryTemplatesPage() {
  const [templates, setTemplates] = useState<InventoryTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showCreateModal, setShowCreateModal] = useState(false);

  useEffect(() => {
    fetchTemplates();
  }, []);

  const fetchTemplates = async () => {
    try {
      const response = await fetch("/api/inventory/templates");
      const result = await response.json();
      if (result.success) {
        setTemplates(result.data);
      } else {
        setError(result.error || "Failed to load templates");
      }
    } catch (err) {
      setError("Network error");
    } finally {
      setLoading(false);
    }
  };

  const handleCreateTemplate = async (template: {
    name: string;
    description: string;
    fieldsSchema: FieldSchema[];
  }) => {
    try {
      const response = await fetch("/api/inventory/templates", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(template),
      });

      const result = await response.json();

      if (result.success) {
        setShowCreateModal(false);
        fetchTemplates();
      } else {
        setError(result.error || "Failed to create template");
      }
    } catch (err) {
      setError("Network error");
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-slate-400">Loading templates...</div>
      </div>
    );
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold text-white">Inventory Templates</h1>
          <p className="text-slate-400">Define the structure for different inventory types</p>
        </div>
        <button
          onClick={() => setShowCreateModal(true)}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
        >
          Create Template
        </button>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-950/50 text-red-400 border border-red-900 rounded-lg">
          {error}
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {templates.map((template) => (
          <div
            key={template.id}
            className="bg-slate-900 border border-slate-800 rounded-lg shadow-sm p-6"
          >
            <div className="flex items-start justify-between mb-4">
              <div>
                <h3 className="text-lg font-semibold text-white">{template.name}</h3>
                {template.description && (
                  <p className="text-sm text-slate-500">{template.description}</p>
                )}
              </div>
              <span
                className={`px-2 py-1 rounded text-xs ${
                  template.isActive
                    ? "bg-green-950 text-green-400 border border-green-900"
                    : "bg-slate-800 text-slate-400 border border-slate-700"
                }`}
              >
                {template.isActive ? "Active" : "Inactive"}
              </span>
            </div>

            <div className="mb-4">
              <h4 className="text-xs font-medium text-slate-500 uppercase mb-2">Fields</h4>
              <div className="space-y-1">
                {template.fieldsSchema.map((field) => (
                  <div
                    key={field.name}
                    className="flex items-center gap-2 text-sm text-slate-300"
                  >
                    <span className="font-mono text-xs bg-slate-800 px-1 rounded text-slate-400">
                      {field.type}
                    </span>
                    <span>{field.label}</span>
                    {field.required && <span className="text-red-400">*</span>}
                  </div>
                ))}
              </div>
            </div>

            <div className="text-xs text-slate-500">
              Created {new Date(template.createdAt).toLocaleDateString()}
            </div>
          </div>
        ))}

        {templates.length === 0 && (
          <div className="col-span-full bg-slate-900 border border-slate-800 rounded-lg shadow-sm p-12 text-center">
            <p className="text-slate-500 mb-4">No inventory templates found.</p>
            <button
              onClick={() => setShowCreateModal(true)}
              className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
            >
              Create Your First Template
            </button>
          </div>
        )}
      </div>

      {showCreateModal && (
        <CreateTemplateModal
          onClose={() => setShowCreateModal(false)}
          onCreate={handleCreateTemplate}
        />
      )}
    </div>
  );
}

interface CreateTemplateModalProps {
  onClose: () => void;
  onCreate: (template: {
    name: string;
    description: string;
    fieldsSchema: FieldSchema[];
  }) => void;
}

function CreateTemplateModal({ onClose, onCreate }: CreateTemplateModalProps) {
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [fields, setFields] = useState<FieldSchema[]>([
    { name: "key", type: "string", required: true, label: "Key" },
  ]);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const addField = () => {
    setFields([
      ...fields,
      {
        name: `field_${fields.length + 1}`,
        type: "string",
        required: false,
        label: `Field ${fields.length + 1}`,
      },
    ]);
  };

  const removeField = (index: number) => {
    if (fields.length > 1) {
      setFields(fields.filter((_, i) => i !== index));
    }
  };

  const updateField = (
    index: number,
    updates: Partial<FieldSchema>
  ) => {
    const newFields = [...fields];
    newFields[index] = { ...newFields[index], ...updates };
    setFields(newFields);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!name.trim()) {
      setError("Template name is required");
      return;
    }

    if (fields.length === 0) {
      setError("At least one field is required");
      return;
    }

    // Validate fields
    for (const field of fields) {
      if (!field.name || !field.label) {
        setError("All fields must have a name and label");
        return;
      }
    }

    setSubmitting(true);

    try {
      await onCreate({
        name: name.trim(),
        description: description.trim() || "",
        fieldsSchema: fields,
      });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-slate-900 border border-slate-800 rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="p-6 border-b border-slate-800">
          <h2 className="text-xl font-bold text-white">Create Inventory Template</h2>
        </div>

        {/* Content */}
        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 space-y-6">
          {error && (
            <div className="p-4 bg-red-950/50 text-red-400 border border-red-900 rounded-lg">
              {error}
            </div>
          )}

          {/* Basic Info */}
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">
              Template Name *
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g., Game Key, Account, Gift Card"
              required
              className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 placeholder:text-slate-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              rows={2}
              placeholder="Optional description"
              className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 placeholder:text-slate-500"
            />
          </div>

          {/* Fields */}
          <div>
            <div className="flex items-center justify-between mb-3">
              <h3 className="text-sm font-medium text-slate-300">Fields Schema</h3>
              <button
                type="button"
                onClick={addField}
                className="text-sm text-blue-400 hover:text-blue-300"
              >
                + Add Field
              </button>
            </div>

            <div className="space-y-3">
              {fields.map((field, index) => (
                <div
                  key={index}
                  className="bg-slate-800/50 p-4 rounded-lg border border-slate-800"
                >
                  <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
                    <div>
                      <label className="block text-xs font-medium text-slate-400 mb-1">
                        Field Name *
                      </label>
                      <input
                        type="text"
                        value={field.name}
                        onChange={(e) => updateField(index, { name: e.target.value })}
                        placeholder="key"
                        required
                        className="w-full px-3 py-2 bg-slate-800 border border-slate-700 text-white rounded focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm placeholder:text-slate-500"
                      />
                    </div>

                    <div>
                      <label className="block text-xs font-medium text-slate-400 mb-1">
                        Label *
                      </label>
                      <input
                        type="text"
                        value={field.label}
                        onChange={(e) => updateField(index, { label: e.target.value })}
                        placeholder="Activation Key"
                        required
                        className="w-full px-3 py-2 bg-slate-800 border border-slate-700 text-white rounded focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm placeholder:text-slate-500"
                      />
                    </div>

                    <div>
                      <label className="block text-xs font-medium text-slate-400 mb-1">
                        Type
                      </label>
                      <select
                        value={field.type}
                        onChange={(e) =>
                          updateField(index, {
                            type: e.target.value as "string" | "number" | "boolean",
                          })
                        }
                        className="w-full px-3 py-2 bg-slate-800 border border-slate-700 text-white rounded focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                      >
                        <option value="string">String</option>
                        <option value="number">Number</option>
                        <option value="boolean">Boolean</option>
                      </select>
                    </div>

                    <div className="flex items-end">
                      <label className="flex items-center gap-2">
                        <input
                          type="checkbox"
                          checked={field.required}
                          onChange={(e) =>
                            updateField(index, { required: e.target.checked })
                          }
                          className="w-4 h-4 text-blue-600 bg-slate-800 border-slate-700 rounded focus:ring-blue-500"
                        />
                        <span className="text-sm text-slate-300">Required</span>
                      </label>
                    </div>

                    <div className="flex items-end">
                      {fields.length > 1 && (
                        <button
                          type="button"
                          onClick={() => removeField(index)}
                          className="px-3 py-2 text-red-400 hover:text-red-300 text-sm"
                        >
                          Remove
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </form>

        {/* Footer */}
        <div className="p-6 border-t border-slate-800 flex justify-end gap-3">
          <button
            type="button"
            onClick={onClose}
            disabled={submitting}
            className="px-4 py-2 border border-slate-700 text-slate-300 rounded-lg hover:bg-slate-800 disabled:opacity-50"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={submitting}
            onClick={handleSubmit}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {submitting ? "Creating..." : "Create Template"}
          </button>
        </div>
      </div>
    </div>
  );
}

/**
 * Manual Sell Delivery Page
 *
 * Display delivered items with copy functionality
 */

"use client";

import { useState, useEffect } from "react";
import { useParams } from "next/navigation";

interface DeliveryItem {
  productId: string;
  productName: string;
  quantity: number;
  items: Array<{
    inventoryId: string;
    values: Record<string, string | number | boolean>;
  }>;
}

interface DeliveryData {
  order: any;
  deliveryItems: DeliveryItem[];
  fromSnapshot: boolean;
}

export default function ManualSellDeliveryPage() {
  const params = useParams();
  const orderId = params.id as string;

  const [data, setData] = useState<DeliveryData | null>(null);
  const [loading, setLoading] = useState(true);
  const [copiedFormat, setCopiedFormat] = useState<string | null>(null);

  useEffect(() => {
    fetchDelivery();
  }, [orderId]);

  const fetchDelivery = async () => {
    try {
      const res = await fetch(`/api/manual-sell/${orderId}`);
      const result = await res.json();

      if (result.success) {
        setData(result.data);
      } else {
        alert("Failed to load delivery data");
      }
    } catch (err) {
      alert("Failed to load delivery data");
    } finally {
      setLoading(false);
    }
  };

  const copyAsTSV = () => {
    if (!data || !data.deliveryItems || !Array.isArray(data.deliveryItems)) return;

    const lines: string[] = [];

    // Header row with field names
    const fieldNames = new Set<string>();
    for (const item of data.deliveryItems) {
      if (item && item.items && Array.isArray(item.items)) {
        for (const row of item.items) {
          if (row && row.values) {
            Object.keys(row.values).forEach((k) => fieldNames.add(k));
          }
        }
      }
    }
    const fields = Array.from(fieldNames);
    lines.push(["Product", ...fields].join("\t"));

    // Data rows
    for (const item of data.deliveryItems) {
      if (item && item.items && Array.isArray(item.items)) {
        for (const row of item.items) {
          if (row && row.values) {
            lines.push([
              item.productName,
              ...fields.map((f) => String(row.values[f] ?? "")),
            ].join("\t"));
          }
        }
      }
    }

    navigator.clipboard.writeText(lines.join("\n"));
    setCopiedFormat("tsv");
    setTimeout(() => setCopiedFormat(null), 2000);
  };

  const copyAsCSV = () => {
    if (!data || !data.deliveryItems || !Array.isArray(data.deliveryItems)) return;

    const lines: string[] = [];

    // Header row
    const fieldNames = new Set<string>();
    for (const item of data.deliveryItems) {
      if (item && item.items && Array.isArray(item.items)) {
        for (const row of item.items) {
          if (row && row.values) {
            Object.keys(row.values).forEach((k) => fieldNames.add(k));
          }
        }
      }
    }
    const fields = Array.from(fieldNames);
    lines.push(["Product", ...fields].join(","));

    // Data rows
    for (const item of data.deliveryItems) {
      if (item && item.items && Array.isArray(item.items)) {
        for (const row of item.items) {
          if (row && row.values) {
            lines.push([
              `"${item.productName}"`,
              ...fields.map((f) => {
                const val = String(row.values[f] ?? "");
                return `"${val.replace(/"/g, '""')}"`;
              }),
            ].join(","));
          }
        }
      }
    }

    navigator.clipboard.writeText(lines.join("\n"));
    setCopiedFormat("csv");
    setTimeout(() => setCopiedFormat(null), 2000);
  };

  const copyFieldAsList = (fieldName: string) => {
    if (!data || !data.deliveryItems || !Array.isArray(data.deliveryItems)) return;

    const values: string[] = [];

    for (const item of data.deliveryItems) {
      if (item && item.items && Array.isArray(item.items)) {
        for (const row of item.items) {
          if (row && row.values) {
            const val = row.values[fieldName];
            if (val) values.push(String(val));
          }
        }
      }
    }

    navigator.clipboard.writeText(values.join("\n"));
    setCopiedFormat(fieldName);
    setTimeout(() => setCopiedFormat(null), 2000);
  };

  // Get all unique field names
  const getAllFields = () => {
    if (!data || !data.deliveryItems || !Array.isArray(data.deliveryItems)) return [];
    const fieldNames = new Set<string>();
    for (const item of data.deliveryItems) {
      if (item && item.items && Array.isArray(item.items)) {
        for (const row of item.items) {
          if (row && row.values) {
            Object.keys(row.values).forEach((k) => fieldNames.add(k));
          }
        }
      }
    }
    return Array.from(fieldNames);
  };

  const allFields = getAllFields();

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-slate-400">Loading delivery data...</div>
      </div>
    );
  }

  if (!data) {
    return (
      <div className="text-center py-12">
        <p className="text-red-400">Failed to load delivery data</p>
      </div>
    );
  }

  const totalItems = data.deliveryItems?.reduce((sum, item) => sum + (item?.quantity || 0), 0) || 0;

  return (
    <div>
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold text-white">Delivery Details</h1>
          <p className="text-slate-400 mt-1">
            Order: {orderId} ÔÇó {totalItems} items delivered
          </p>
        </div>
        <div className="flex gap-2">
          <button
            onClick={copyAsTSV}
            className="px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg transition-colors flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
            </svg>
            Copy TSV
          </button>
          <button
            onClick={copyAsCSV}
            className="px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg transition-colors flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
            </svg>
            Copy CSV
          </button>
        </div>
      </div>

      {/* Copy confirmation */}
      {copiedFormat && (
        <div className="mb-4 p-3 bg-green-500/20 border border-green-500/30 rounded-lg text-green-400 text-center">
          Copied as {copiedFormat === "tsv" || copiedFormat === "csv" ? copiedFormat.toUpperCase() : copiedFormat}!
        </div>
      )}

      {/* Quick Copy Buttons */}
      {allFields.length > 0 && (
        <div className="mb-6 p-4 bg-slate-800 rounded-lg border border-slate-700">
          <h3 className="text-sm font-medium text-slate-300 mb-3">Quick Copy Field Values:</h3>
          <div className="flex flex-wrap gap-2">
            {allFields.map((field) => (
              <button
                key={field}
                onClick={() => copyFieldAsList(field)}
                className="px-3 py-1.5 bg-slate-700 hover:bg-slate-600 text-white text-sm rounded transition-colors"
              >
                Copy "{field}"
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Delivery Items Table */}
      <div className="bg-slate-800 rounded-lg border border-slate-700 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-slate-900/50">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                  #
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                  Product
                </th>
                {allFields.map((field) => (
                  <th
                    key={field}
                    className="px-4 py-3 text-left text-xs font-medium text-slate-400 uppercase"
                  >
                    {field}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-700">
              {data.deliveryItems && Array.isArray(data.deliveryItems) && data.deliveryItems.map((deliveryItem) =>
                deliveryItem.items && Array.isArray(deliveryItem.items) ? deliveryItem.items.map((row, idx) => (
                  <tr key={row.inventoryId} className="hover:bg-slate-700/30">
                    <td className="px-4 py-3 text-sm text-slate-400">
                      {idx + 1}
                    </td>
                    <td className="px-4 py-3 text-sm font-medium text-white">
                      {deliveryItem.productName || "-"}
                    </td>
                    {allFields.map((field) => (
                      <td key={field} className="px-4 py-3 text-sm text-slate-300 font-mono">
                        {String((row.values && row.values[field]) ?? "-")}
                      </td>
                    ))}
                  </tr>
                )) : null
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

/**
 * Manual Sell Page
 *
 * Manual sales workflow with shortage handling
 */

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";

interface Product {
  id: string;
  name: string;
  price: string;
  stockCount: number;
  templateName: string | null;
  inventoryTemplateId: string | null;
  templateFields?: TemplateField[];
}

interface SellItem {
  productId: string;
  quantity: number;
  productName: string;
  available: number;
}

interface ShortageItem {
  productId: string;
  productName: string;
  requested: number;
  available: number;
  shortage: number;
}

interface AvailabilityCheck {
  hasShortage: boolean;
  shortageItems: ShortageItem[];
  potentialDelivery: Array<{
    productId: string;
    productName: string;
    requested: number;
    available: number;
    canDeliver: number;
    shortage: number;
    subtotalIfPartial: string;
  }>;
  totals: {
    requested: string;
    canDeliver: string;
  };
  options: {
    partial?: string;
    addInventory?: string;
    pending?: string;
    complete?: string;
  };
}

interface OrderResult {
  orderId: string;
  order: any;
  deliveryItems: Array<{
    productId: string;
    productName: string;
    quantity: number;
    items: Array<{
      inventoryId: string;
      values: Record<string, string | number | boolean>;
    }>;
  }>;
  shortageItems: ShortageItem[];
  hasShortage: boolean;
}

interface TemplateField {
  name: string;
  type: "string" | "number" | "boolean";
  label: string;
  required: boolean;
}

export default function ManualSellPage() {
  const router = useRouter();
  const [products, setProducts] = useState<Product[]>([]);
  const [templates, setTemplates] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [sellItems, setSellItems] = useState<SellItem[]>([]);
  const [customerEmail, setCustomerEmail] = useState("");
  const [customerName, setCustomerName] = useState("");
  const [processing, setProcessing] = useState(false);
  const [orderResult, setOrderResult] = useState<OrderResult | null>(null);
  const [shortageModal, setShortageModal] = useState<{
    show: boolean;
    data: AvailabilityCheck | null;
  }>({ show: false, data: null });

  useEffect(() => {
    fetchProducts();
    fetchTemplates();
  }, []);

  const fetchProducts = async () => {
    try {
      const res = await fetch("/api/products/summary?limit=100");
      const data = await res.json();
      if (data.success) {
        // Also fetch template info for each product
        const productsWithTemplates = await Promise.all(
          data.data.map(async (p: any) => {
            // Get template fields
            if (p.inventoryTemplateId) {
              const templateRes = await fetch("/api/inventory/templates");
              const templateData = await templateRes.json();
              if (templateData.success) {
                const template = templateData.data.find((t: any) => t.id === p.inventoryTemplateId);
                return {
                  ...p,
                  templateFields: template?.fieldsSchema || [],
                };
              }
            }
            return { ...p, templateFields: [] };
          })
        );
        setProducts(productsWithTemplates.filter((p: Product) => (p as any).isActive !== false));
      }
    } catch (err) {
      console.error("Failed to load products");
    } finally {
      setLoading(false);
    }
  };

  const fetchTemplates = async () => {
    try {
      const res = await fetch("/api/inventory/templates");
      const data = await res.json();
      if (data.success) {
        setTemplates(data.data);
      }
    } catch (err) {
      console.error("Failed to load templates");
    }
  };

  const addSellItem = (productId: string, quantity: number) => {
    const product = products.find((p) => p.id === productId);
    if (!product) return;

    const existingIndex = sellItems.findIndex((i) => i.productId === productId);

    if (existingIndex >= 0) {
      const newItems = [...sellItems];
      newItems[existingIndex].quantity += quantity;
      setSellItems(newItems);
    } else {
      setSellItems([
        ...sellItems,
        {
          productId: product.id,
          quantity,
          productName: product.name,
          available: product.stockCount,
        },
      ]);
    }
  };

  const updateSellItemQuantity = (productId: string, quantity: number) => {
    setSellItems(
      sellItems
        .map((item) =>
          item.productId === productId ? { ...item, quantity } : item
        )
        .filter((item) => item.quantity > 0)
    );
  };

  const removeSellItem = (productId: string) => {
    setSellItems(sellItems.filter((item) => item.productId !== productId));
  };

  const checkAvailability = async () => {
    if (sellItems.length === 0) {
      alert("Please add items to sell");
      return null;
    }

    if (!customerEmail) {
      alert("Please enter customer email");
      return null;
    }

    setProcessing(true);
    try {
      const res = await fetch("/api/manual-sell", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          items: sellItems.map((i) => ({ productId: i.productId, quantity: i.quantity })),
          customerEmail,
          customerName: customerName || undefined,
        }),
      });

      const data = await res.json();

      if (data.success && data.action === "check") {
        return data.data;
      } else if (data.success && data.data.orderId) {
        // Sale completed directly (no shortage)
        setOrderResult(data.data);
        return null;
      } else {
        alert(data.error || "Failed to check availability");
        return null;
      }
    } catch (err) {
      alert("Failed to check availability");
      return null;
    } finally {
      setProcessing(false);
    }
  };

  const processSale = async (action?: "partial" | "add-inventory" | "pending", inventoryItemsToAdd?: Array<{ productId: string; values: Record<string, string | number | boolean> }>) => {
    setProcessing(true);
    try {
      const res = await fetch("/api/manual-sell", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          items: sellItems.map((i) => ({ productId: i.productId, quantity: i.quantity })),
          customerEmail,
          customerName: customerName || undefined,
          shortageAction: action,
          inventoryItemsToAdd,
        }),
      });

      const data = await res.json();

      if (data.success) {
        setOrderResult(data.data);
        setShortageModal({ show: false, data: null });
      } else {
        alert(data.error || "Sale failed");
      }
    } catch (err) {
      alert("Sale failed");
    } finally {
      setProcessing(false);
    }
  };

  const handleCompleteSale = async () => {
    const availability = await checkAvailability();
    if (availability) {
      setShortageModal({ show: true, data: availability });
    }
  };

  const resetSale = () => {
    setOrderResult(null);
    setSellItems([]);
    setCustomerEmail("");
    setCustomerName("");
    setShortageModal({ show: false, data: null });
  };

  const viewDelivery = () => {
    if (orderResult) {
      router.push(`/dashboard/manual-sell/${orderResult.orderId}`);
    }
  };

  // Calculate totals
  const totalItems = sellItems.reduce((sum, item) => sum + item.quantity, 0);
  const totalValue = sellItems.reduce((sum, item) => {
    const product = products.find((p) => p.id === item.productId);
    return sum + (parseFloat(product?.price || "0") * item.quantity);
  }, 0);

  return (
    <div>
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-white">Manual Sell</h1>
        <p className="text-slate-400 mt-1">
          Process manual sales with shortage handling
        </p>
      </div>

      {orderResult ? (
        <OrderConfirmation
          result={orderResult}
          onReset={resetSale}
          onViewDelivery={viewDelivery}
        />
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Product Selection */}
          <div className="lg:col-span-2">
            <div className="bg-slate-800 rounded-lg border border-slate-700 p-6">
              <h2 className="text-lg font-semibold text-white mb-4">Select Products</h2>

              {loading ? (
                <div className="text-center py-8 text-slate-400">Loading products...</div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-h-[600px] overflow-y-auto">
                  {products.map((product: any) => (
                    <ProductCard
                      key={product.id}
                      product={product}
                      onAdd={addSellItem}
                      currentQuantity={
                        sellItems.find((i) => i.productId === product.id)?.quantity || 0
                      }
                    />
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Sale Summary */}
          <div>
            <div className="bg-slate-800 rounded-lg border border-slate-700 p-6 sticky top-6">
              <h2 className="text-lg font-semibold text-white mb-4">Sale Summary</h2>

              {/* Customer Info */}
              <div className="space-y-3 mb-6">
                <div>
                  <label className="block text-sm text-slate-400 mb-1">
                    Customer Email *
                  </label>
                  <input
                    type="email"
                    value={customerEmail}
                    onChange={(e) => setCustomerEmail(e.target.value)}
                    className="w-full px-3 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                    placeholder="customer@example.com"
                  />
                </div>
                <div>
                  <label className="block text-sm text-slate-400 mb-1">
                    Customer Name
                  </label>
                  <input
                    type="text"
                    value={customerName}
                    onChange={(e) => setCustomerName(e.target.value)}
                    className="w-full px-3 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                    placeholder="Optional"
                  />
                </div>
              </div>

              {/* Items List */}
              {sellItems.length > 0 ? (
                <>
                  <div className="space-y-2 mb-6">
                    {sellItems.map((item) => {
                      const hasShortage = item.quantity > item.available;
                      return (
                        <div
                          key={item.productId}
                          className="flex items-center justify-between p-3 bg-slate-900 rounded-lg"
                        >
                          <div className="flex-1 min-w-0">
                            <p className="text-sm font-medium text-white truncate">
                              {item.productName}
                            </p>
                            <p className="text-xs text-slate-400">
                              Qty: {item.quantity}{" "}
                              {hasShortage && (
                                <span className="text-yellow-400">
                                  (only {item.available} available)
                                </span>
                              )}
                            </p>
                          </div>
                          <div className="flex items-center gap-2">
                            <button
                              onClick={() => updateSellItemQuantity(item.productId, item.quantity - 1)}
                              className="w-8 h-8 flex items-center justify-center bg-slate-700 hover:bg-slate-600 rounded text-white"
                            >
                              -
                            </button>
                            <span className="w-8 text-center text-white">{item.quantity}</span>
                            <button
                              onClick={() => updateSellItemQuantity(item.productId, item.quantity + 1)}
                              className="w-8 h-8 flex items-center justify-center bg-slate-700 hover:bg-slate-600 rounded text-white"
                            >
                              +
                            </button>
                            <button
                              onClick={() => removeSellItem(item.productId)}
                              className="ml-2 p-1 text-red-400 hover:text-red-300"
                            >
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                              </svg>
                            </button>
                          </div>
                        </div>
                      );
                    })}
                  </div>

                  {/* Totals */}
                  <div className="border-t border-slate-700 pt-4 mb-4">
                    <div className="flex justify-between text-sm text-slate-400 mb-2">
                      <span>Total Items:</span>
                      <span className="text-white">{totalItems}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-slate-400">Total Value:</span>
                      <span className="text-xl font-bold text-white">
                        ${totalValue.toFixed(2)}
                      </span>
                    </div>
                  </div>

                  {/* Submit */}
                  <button
                    onClick={handleCompleteSale}
                    disabled={processing || sellItems.length === 0}
                    className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {processing ? "Processing..." : "Complete Sale"}
                  </button>
                </>
              ) : (
                <div className="text-center py-8 text-slate-400">
                  No items added yet
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Shortage Options Modal */}
      {shortageModal.show && shortageModal.data && (
        <ShortageOptionsModal
          data={shortageModal.data}
          onClose={() => setShortageModal({ show: false, data: null })}
          onPartialSale={() => processSale("partial")}
          onPendingSale={() => processSale("pending")}
          onAddInventory={(inventory) => processSale("add-inventory", inventory)}
          products={products}
          templates={templates}
        />
      )}
    </div>
  );
}

// Product Card Component
function ProductCard({
  product,
  onAdd,
  currentQuantity,
}: {
  product: Product;
  onAdd: (productId: string, quantity: number) => void;
  currentQuantity: number;
}) {
  const [quantity, setQuantity] = useState(1);

  const handleAdd = () => {
    onAdd(product.id, quantity);
    setQuantity(1);
  };

  return (
    <div className="bg-slate-900 rounded-lg p-4 border border-slate-700">
      <div className="flex justify-between items-start mb-2">
        <h3 className="font-medium text-white truncate flex-1">{product.name}</h3>
        <span className="text-sm text-green-400 ml-2">{product.stockCount} avail</span>
      </div>
      <p className="text-lg font-bold text-white mb-3">${product.price}</p>
      <div className="flex items-center gap-2">
        <input
          type="number"
          min={1}
          value={quantity}
          onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
          className="w-20 px-2 py-1 bg-slate-800 border border-slate-700 rounded text-white text-center"
        />
        <button
          onClick={handleAdd}
          className="flex-1 py-1 bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium rounded transition-colors"
        >
          Add
        </button>
      </div>
      {currentQuantity > 0 && (
        <div className="mt-2 text-xs text-slate-400">
          In cart: {currentQuantity}
        </div>
      )}
    </div>
  );
}

