              </p>
            </div>
            <a
              href="/dashboard/platforms"
              target="_blank"
              className="text-sm text-blue-400 hover:text-blue-300"
            >
              + Manage Platforms
            </a>
          </div>

          <PlatformTreeSelect
            value={platformIds}
            onChange={setPlatformIds}
          />
        </div>

        {/* Images */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-semibold text-white">Images</h2>
            <button
              type="button"
              onClick={addImage}
              className="text-sm text-blue-400 hover:text-blue-300"
            >
              + Add Image
            </button>
          </div>

          {images.map((image, index) => (
            <div key={index} className="flex gap-4 mb-3 items-start">
              <div className="flex-1">
                <input
                  type="url"
                  value={image.url}
                  onChange={(e) => updateImage(index, "url", e.target.value)}
                  placeholder="Image URL (https://...)"
                  className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 placeholder:text-slate-500"
                />
              </div>
              <input
                type="text"
                value={image.alt || ""}
                onChange={(e) => updateImage(index, "alt", e.target.value)}
                placeholder="Alt text"
                className="w-40 px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 placeholder:text-slate-500"
              />
              {images.length > 1 && (
                <button
                  type="button"
                  onClick={() => removeImage(index)}
                  className="px-3 py-2 text-red-400 hover:text-red-300 mt-1"
                >
                  Remove
                </button>
              )}
            </div>
          ))}
        </div>

        {/* Actions */}
        <div className="flex justify-end gap-4 pt-6 border-t border-slate-800">
          <button
            type="button"
            onClick={() => router.back()}
            className="px-6 py-2 border border-slate-700 text-slate-300 rounded-lg hover:bg-slate-800"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {loading ? "Creating..." : "Create Product"}
          </button>
        </div>
      </form>
    </div>
  );
}

"use client";

/**
 * Activity Logs Table Component
 *
 * Displays audit trail of all admin/staff actions
 */

import { useEffect, useState } from "react";

interface ActivityLog {
  id: string;
  userId: string | null;
  action: string;
  entity: string;
  entityId: string;
  metadata: Record<string, unknown> | null;
  ipAddress: string | null;
  createdAt: string;
  user: {
    name: string;
    email: string;
    role: "admin" | "staff";
  } | null;
}

export function ActivityLogsTable() {
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [actionFilter, setActionFilter] = useState<string>("");
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  useEffect(() => {
    async function fetchLogs() {
      try {
        const params = new URLSearchParams({
          page: page.toString(),
          limit: "50",
        });
        if (actionFilter) params.set("action", actionFilter);

        const response = await fetch(`/api/activity-logs?${params}`);
        const result = await response.json();

        if (result.success) {
          setLogs(result.data);
          setTotalPages(result.pagination.totalPages);
        } else {
          setError(result.error || "Failed to load activity logs");
        }
      } catch (err) {
        setError("Network error");
      } finally {
        setLoading(false);
      }
    }

    fetchLogs();
  }, [page, actionFilter]);

  const getActionColor = (action: string) => {
    if (action.includes("created") || action.includes("added"))
      return "text-green-400";
    if (action.includes("deleted") || action.includes("cancelled"))
      return "text-red-400";
    if (action.includes("updated")) return "text-blue-400";
    return "text-slate-400";
  };

  const formatAction = (action: string) => {
    return action
      .split("_")
      .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
      .join(" ");
  };

  const formatEntity = (entity: string) => {
    return entity.charAt(0).toUpperCase() + entity.slice(1);
  };

  if (loading) {
    return (
      <div className="bg-slate-900 border border-slate-800 rounded-lg shadow-sm p-6">
        <div className="animate-pulse space-y-4">
          {[...Array(10)].map((_, i) => (
            <div key={i} className="h-14 bg-slate-800 rounded" />
          ))}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-950/50 text-red-400 border border-red-900 p-4 rounded-lg">
        Error loading activity logs: {error}
      </div>
    );
  }

  return (
    <div className="bg-slate-900 border border-slate-800 rounded-lg shadow-sm overflow-hidden">
      {/* Filters */}
      <div className="p-4 border-b border-slate-800">
        <div className="flex gap-4">
          <select
            value={actionFilter}
            onChange={(e) => {
              setActionFilter(e.target.value);
              setPage(1);
            }}
            className="px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="">All Actions</option>
            <option value="product_created">Product Created</option>
            <option value="product_updated">Product Updated</option>
            <option value="product_deleted">Product Deleted</option>
            <option value="order_completed">Order Completed</option>
            <option value="inventory_added">Inventory Added</option>
            <option value="coupon_created">Coupon Created</option>
            <option value="staff_created">Staff Created</option>
            <option value="login">Login</option>
          </select>
        </div>
      </div>

      {/* Table */}
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead className="bg-slate-800">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Action
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Entity
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                User
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                IP Address
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Timestamp
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {logs.map((log) => (
              <tr key={log.id} className="hover:bg-slate-800">
                <td className="px-6 py-4">
                  <span className={`font-medium ${getActionColor(log.action)}`}>
                    {formatAction(log.action)}
                  </span>
                </td>
                <td className="px-6 py-4 text-sm text-slate-300">
                  <div>
                    <span className="font-medium text-white">{formatEntity(log.entity)}</span>
                    <span className="text-slate-500 ml-1 font-mono text-xs">
                      ({log.entityId.slice(0, 8)}...)
                    </span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  {log.user ? (
                    <div>
                      <p className="font-medium text-white">
                        {log.user.name}
                      </p>
                      <p className="text-sm text-slate-500">{log.user.email}</p>
                    </div>
                  ) : (
                    <span className="text-slate-500">System</span>
                  )}
                </td>
                <td className="px-6 py-4 text-sm text-slate-500 font-mono">
                  {log.ipAddress || "-"}
                </td>
                <td className="px-6 py-4 text-sm text-slate-400">
                  {new Date(log.createdAt).toLocaleString()}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="px-6 py-4 border-t border-slate-800 flex items-center justify-between">
          <p className="text-sm text-slate-500">
            Page {page} of {totalPages}
          </p>
          <div className="flex gap-2">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="px-4 py-2 border border-slate-700 text-slate-300 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-800"
            >
              Previous
            </button>
            <button
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              className="px-4 py-2 border border-slate-700 text-slate-300 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-800"
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

/**
 * Add Coupon Modal Component
 *
 * Modal form to create a new discount coupon
 */

import { useState } from "react";

interface AddCouponModalProps {
  onClose: () => void;
  onAdded: () => void;
}

export function AddCouponModal({ onClose, onAdded }: AddCouponModalProps) {
  const [code, setCode] = useState("");
  const [description, setDescription] = useState("");
  const [discountType, setDiscountType] = useState<"percentage" | "fixed">("percentage");
  const [discountValue, setDiscountValue] = useState("");
  const [minPurchase, setMinPurchase] = useState("0");
  const [usageLimit, setUsageLimit] = useState<string>("");
  const [validFrom, setValidFrom] = useState(
    new Date().toISOString().split("T")[0]
  );
  const [validUntil, setValidUntil] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!code.trim() || !discountValue) {
      setError("Code and discount value are required");
      return;
    }

    const value = parseFloat(discountValue);
    if (isNaN(value) || value <= 0) {
      setError("Discount value must be a positive number");
      return;
    }

    if (discountType === "percentage" && value > 100) {
      setError("Percentage discount cannot exceed 100%");
      return;
    }

    setLoading(true);

    try {
      const response = await fetch("/api/coupons", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          code: code.trim().toUpperCase(),
          description: description.trim() || null,
          discountType,
          discountValue: value.toString(),
          minPurchase: minPurchase || "0",
          usageLimit: usageLimit ? parseInt(usageLimit) : null,
          validFrom: new Date(validFrom).toISOString(),
          validUntil: validUntil ? new Date(validUntil).toISOString() : null,
        }),
      });

      const result = await response.json();

      if (result.success) {
        onAdded();
      } else {
        setError(result.error || "Failed to create coupon");
      }
    } catch (err) {
      setError("Network error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-lg">
        {/* Header */}
        <div className="p-6 border-b border-slate-200 flex items-center justify-between">
          <h2 className="text-xl font-bold text-slate-800">Create Coupon</h2>
          <button
            onClick={onClose}
            className="text-slate-400 hover:text-slate-600 text-2xl"
          >
            &times;
          </button>
        </div>

        {/* Content */}
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {error && (
            <div className="p-4 bg-red-50 text-red-600 rounded-lg text-sm">
              {error}
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                Coupon Code *
              </label>
              <input
                type="text"
                value={code}
                onChange={(e) => setCode(e.target.value.toUpperCase())}
                required
                placeholder="SUMMER2024"
                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                Discount Type *
              </label>
              <select
                value={discountType}
                onChange={(e) => setDiscountType(e.target.value as "percentage" | "fixed")}
                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="percentage">Percentage (%)</option>
                <option value="fixed">Fixed Amount ($)</option>
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              Discount Value *
            </label>
            <div className="flex items-center gap-2">
              {discountType === "percentage" && (
                <span className="text-slate-500">%</span>
              )}
              <input
                type="number"
                step="0.01"
                min="0"
                max={discountType === "percentage" ? 100 : undefined}
                value={discountValue}
                onChange={(e) => setDiscountValue(e.target.value)}
                required
                placeholder={discountType === "percentage" ? "10-100" : "0.00"}
                className="flex-1 px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
              {discountType === "fixed" && (
                <span className="text-slate-500">USD</span>
              )}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                Min Purchase (USD)
              </label>
              <input
                type="number"
                step="0.01"
                min="0"
                value={minPurchase}
                onChange={(e) => setMinPurchase(e.target.value)}
                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="0.00"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                Usage Limit
              </label>
              <input
                type="number"
                min="1"
                value={usageLimit}
                onChange={(e) => setUsageLimit(e.target.value)}
                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="Unlimited"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              rows={2}
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="Optional description"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                Valid From *
              </label>
              <input
                type="date"
                value={validFrom}
                onChange={(e) => setValidFrom(e.target.value)}
                required
                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                Valid Until
              </label>
              <input
                type="date"
                value={validUntil}
                onChange={(e) => setValidUntil(e.target.value)}
                min={validFrom}
                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          {/* Footer */}
          <div className="flex justify-end gap-3 pt-4 border-t border-slate-200">
            <button
              type="button"
              onClick={onClose}
              disabled={loading}
              className="px-4 py-2 border border-slate-300 rounded-lg hover:bg-slate-50 disabled:opacity-50"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? "Creating..." : "Create Coupon"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

/**
 * Add Inventory Modal Component
 *
 * Modal form to bulk add inventory items for a product
 */

import { useState, useEffect } from "react";

interface Product {
  id: string;
  name: string;
  slug: string;
}

interface InventoryTemplate {
  id: string;
  name: string;
  fieldsSchema: Array<{
    name: string;
    type: "string" | "number" | "boolean";
    required: boolean;
    label: string;
  }>;
}

interface AddInventoryModalProps {
  onClose: () => void;
  productId?: string;
}

export function AddInventoryModal({ onClose, productId }: AddInventoryModalProps) {
  const [products, setProducts] = useState<Product[]>([]);
  const [templates, setTemplates] = useState<InventoryTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  const [selectedProductId, setSelectedProductId] = useState(productId || "");
  const [selectedTemplateId, setSelectedTemplateId] = useState("");
  const [inventoryItems, setInventoryItems] = useState<Record<string, unknown>[]>([]);
  const [currentItem, setCurrentItem] = useState<Record<string, unknown>>({});
  const [bulkText, setBulkText] = useState("");

  // Selected template's schema
  const selectedTemplate = templates.find((t) => t.id === selectedTemplateId);

  useEffect(() => {
    async function loadData() {
      try {
        const [productsRes, templatesRes] = await Promise.all([
          fetch("/api/products"),
          fetch("/api/inventory/templates"),
        ]);

        const productsResult = await productsRes.json();
        const templatesResult = await templatesRes.json();

        if (productsResult.success) {
          setProducts(productsResult.data);
        }
        if (templatesResult.success) {
          setTemplates(templatesResult.data);
        }
      } catch (err) {
        console.error("Failed to load data:", err);
      } finally {
        setLoading(false);
      }
    }
    loadData();
  }, []);

  // When product changes, update template if product has one
  useEffect(() => {
    if (selectedProductId) {
      const product = products.find((p) => p.id === selectedProductId);
      // We would need to fetch product details to get inventoryTemplateId
      // For now, let user select template manually
    }
  }, [selectedProductId, products]);

  const updateCurrentItemField = (fieldName: string, value: string | number | boolean) => {
    setCurrentItem({ ...currentItem, [fieldName]: value });
  };

  const addItem = () => {
    if (selectedTemplate) {
      // Validate required fields
      const missing = selectedTemplate.fieldsSchema
        .filter((f) => f.required && !currentItem[f.name])
        .map((f) => f.label);

      if (missing.length > 0) {
        setError(`Missing required fields: ${missing.join(", ")}`);
        return;
      }

      setInventoryItems([...inventoryItems, { ...currentItem }]);
      setCurrentItem({});
      setError(null);
    }
  };

  const removeItem = (index: number) => {
    setInventoryItems(inventoryItems.filter((_, i) => i !== index));
  };

  const handleBulkSubmit = () => {
    if (!selectedTemplate || !bulkText.trim()) return;

    const lines = bulkText.split("\n").filter((line) => line.trim());
    const parsedItems: Record<string, unknown>[] = [];

    lines.forEach((line) => {
      const values: Record<string, unknown> = {};
      const parts = line.split(",").map((p) => p.trim());

      selectedTemplate.fieldsSchema.forEach((field, index) => {
        if (index < parts.length) {
          const value = parts[index];
          if (field.type === "number") {
            values[field.name] = parseFloat(value);
          } else if (field.type === "boolean") {
            values[field.name] = value.toLowerCase() === "true";
          } else {
            values[field.name] = value;
          }
        }
      });

      parsedItems.push(values);
    });

    setInventoryItems([...inventoryItems, ...parsedItems]);
    setBulkText("");
  };

  const handleSubmit = async () => {
    if (!selectedProductId || inventoryItems.length === 0) {
      setError("Please select a product and add at least one inventory item");
      return;
    }

    setSubmitting(true);
    setError(null);

    try {
      const response = await fetch("/api/inventory", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productId: selectedProductId,
          items: inventoryItems,
        }),
      });

      const result = await response.json();

      if (result.success) {
        setSuccess(true);
        setTimeout(() => {
          onClose();
          window.location.reload();
        }, 1500);
      } else {
        setError(result.error || "Failed to add inventory");
      }
    } catch (err) {
      setError("Network error");
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
        <div className="bg-slate-900 border border-slate-800 rounded-lg p-6 text-white">Loading...</div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-slate-900 border border-slate-800 rounded-lg shadow-xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
          <h2 className="text-xl font-bold text-white">Add Inventory Items</h2>
          <button
            onClick={onClose}
            className="text-slate-400 hover:text-slate-200 text-2xl"
          >
            &times;
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {success ? (
            <div className="text-center py-8">
              <div className="text-green-400 text-5xl mb-4">Ô£ô</div>
              <h3 className="text-lg font-semibold text-white mb-2">Inventory Added Successfully!</h3>
              <p className="text-slate-400">{inventoryItems.length} items have been added.</p>
            </div>
          ) : (
            <div className="space-y-6">
              {error && (
                <div className="p-4 bg-red-950/50 text-red-400 border border-red-900 rounded-lg">
                  {error}
                </div>
              )}

              {/* Product Selection */}
              <div>
                <label className="block text-sm font-medium text-slate-300 mb-2">
                  Product *
                </label>
                <select
                  value={selectedProductId}
                  onChange={(e) => setSelectedProductId(e.target.value)}
                  disabled={!!productId}
                  className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-slate-850"
                >
                  <option value="">Select a product...</option>
                  {products.map((product) => (
                    <option key={product.id} value={product.id}>
                      {product.name}
                    </option>
                  ))}
                </select>
              </div>

              {/* Template Selection */}
              <div>
                <label className="block text-sm font-medium text-slate-300 mb-2">
                  Inventory Template *
                </label>
                <select
                  value={selectedTemplateId}
                  onChange={(e) => setSelectedTemplateId(e.target.value)}
                  className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  <option value="">Select a template...</option>
                  {templates.map((template) => (
                    <option key={template.id} value={template.id}>
                      {template.name}
                    </option>
                  ))}
                </select>
              </div>

              {selectedTemplate && (
                <>
                  {/* Tabs for Single vs Bulk */}
                  <div className="border-b border-slate-800">
                    <div className="flex gap-4">
                      <button
                        type="button"
                        onClick={() => setBulkText("")}
                        className="px-4 py-2 border-b-2 border-blue-500 text-blue-400 font-medium"
                      >
                        Single Item
                      </button>
                      <button
                        type="button"
                        onClick={() => setCurrentItem({})}
                        className="px-4 py-2 text-slate-400 hover:text-slate-200"
                      >
                        Bulk Import (CSV)
                      </button>
                    </div>
                  </div>

                  {/* Single Item Form */}
                  <div className="bg-slate-800/50 p-4 rounded-lg border border-slate-800">
                    <h3 className="text-sm font-medium text-slate-300 mb-3">
                      Add Single Item
                    </h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {selectedTemplate.fieldsSchema.map((field) => (
                        <div key={field.name}>
                          <label className="block text-sm font-medium text-slate-300 mb-1">
                            {field.label}
                            {field.required && <span className="text-red-400 ml-1">*</span>}
                          </label>
                          {field.type === "boolean" ? (
                            <select
                              value={String(currentItem[field.name] ?? "")}
                              onChange={(e) =>
                                updateCurrentItemField(field.name, e.target.value === "true")
                              }
                              className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                            >
                              <option value="">Select...</option>
                              <option value="true">True</option>
                              <option value="false">False</option>
                            </select>
                          ) : field.type === "number" ? (
                            <input
                              type="number"
                              value={String(currentItem[field.name] ?? "")}
                              onChange={(e) =>
                                updateCurrentItemField(field.name, parseFloat(e.target.value))
                              }
                              required={field.required}
                              className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 placeholder:text-slate-500"
                            />
                          ) : (
                            <input
                              type="text"
                              value={String(currentItem[field.name] ?? "")}
                              onChange={(e) => updateCurrentItemField(field.name, e.target.value)}
                              required={field.required}
                              className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 placeholder:text-slate-500"
                            />
                          )}
                        </div>
                      ))}
                    </div>
                    <button
                      type="button"
                      onClick={addItem}
                      className="mt-4 px-4 py-2 bg-slate-700 text-slate-200 rounded-lg hover:bg-slate-600"
                    >
                      + Add to List
                    </button>
                  </div>

                  {/* Bulk Import */}
                  <div className="bg-slate-800/50 p-4 rounded-lg border border-slate-800">
                    <h3 className="text-sm font-medium text-slate-300 mb-3">
                      Bulk Import (CSV Format)
                    </h3>
                    <p className="text-xs text-slate-500 mb-2">
                      Enter one item per line, comma-separated values in order:{" "}
                      {selectedTemplate.fieldsSchema.map((f) => f.label).join(", ")}
                    </p>
                    <textarea
                      value={bulkText}
                      onChange={(e) => setBulkText(e.target.value)}
                      rows={5}
                      placeholder={`XXXXX-XXXXX-XXXXX\nXXXXX-XXXXX-XXXXX\nXXXXX-XXXXX-XXXXX`}
                      className="w-full px-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono text-sm placeholder:text-slate-500"
                    />
                    <button
                      type="button"
                      onClick={handleBulkSubmit}
                      className="mt-2 px-4 py-2 bg-slate-700 text-slate-200 rounded-lg hover:bg-slate-600"
                    >
                      Parse & Add Items
                    </button>
                  </div>

                  {/* Items List */}
                  {inventoryItems.length > 0 && (
                    <div>
                      <h3 className="text-sm font-medium text-slate-300 mb-2">
                        Items to Add ({inventoryItems.length})
                      </h3>
                      <div className="border border-slate-800 rounded-lg max-h-48 overflow-y-auto bg-slate-800/30">
                        {inventoryItems.map((item, index) => (
                          <div
                            key={index}
                            className="flex items-center justify-between p-3 border-b border-slate-800 last:border-b-0"
                          >
                            <div className="text-sm font-mono text-slate-400">
                              {JSON.stringify(item)}
                            </div>
                            <button
                              type="button"
                              onClick={() => removeItem(index)}
                              className="text-red-400 hover:text-red-300 text-sm"
                            >
                              Remove
                            </button>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-slate-800 flex justify-end gap-3">
          <button
            type="button"
            onClick={onClose}
            disabled={submitting || success}
            className="px-4 py-2 border border-slate-700 text-slate-300 rounded-lg hover:bg-slate-800 disabled:opacity-50"
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={handleSubmit}
            disabled={submitting || success || inventoryItems.length === 0}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {submitting ? "Adding..." : `Add ${inventoryItems.length} Item${inventoryItems.length !== 1 ? "s" : ""}`}
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

/**
 * Add Staff Modal Component
 *
 * Modal form to add a new staff member
 */

import { useState } from "react";

interface AddStaffModalProps {
  onClose: () => void;
  onAdded: () => void;
}

export function AddStaffModal({ onClose, onAdded }: AddStaffModalProps) {
  const [email, setEmail] = useState("");
  const [name, setName] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [role, setRole] = useState<"admin" | "staff">("staff");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!email || !name || !password) {
      setError("All fields are required");
      return;
    }

    if (password.length < 8) {
      setError("Password must be at least 8 characters");
      return;
    }

    if (password !== confirmPassword) {
      setError("Passwords do not match");
      return;
    }

    setLoading(true);

    try {
      const response = await fetch("/api/staff", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, name, password, role }),
      });

      const result = await response.json();

      if (result.success) {
        onAdded();
      } else {
        setError(result.error || "Failed to create staff member");
      }
    } catch (err) {
      setError("Network error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-md">
        {/* Header */}
        <div className="p-6 border-b border-slate-200 flex items-center justify-between">
          <h2 className="text-xl font-bold text-slate-800">Add Staff Member</h2>
          <button
            onClick={onClose}
            className="text-slate-400 hover:text-slate-600 text-2xl"
          >
            &times;
          </button>
        </div>

        {/* Content */}
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {error && (
            <div className="p-4 bg-red-50 text-red-600 rounded-lg text-sm">
              {error}
            </div>
          )}

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              Name *
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="John Doe"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              Email *
            </label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="john@example.com"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              Role *
            </label>
            <select
              value={role}
              onChange={(e) => setRole(e.target.value as "admin" | "staff")}
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="staff">Staff</option>
              <option value="admin">Admin</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              Password *
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              minLength={8}
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="Min 8 characters"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              Confirm Password *
            </label>
            <input
              type="password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="Re-enter password"
            />
          </div>

          {/* Footer */}
          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              disabled={loading}
              className="px-4 py-2 border border-slate-300 rounded-lg hover:bg-slate-50 disabled:opacity-50"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? "Creating..." : "Add Staff Member"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

/**
