/**
 * Platform Modal Component
 *
 * Modal for creating/editing platforms
 */

"use client";

import { useState, useEffect } from "react";

interface Platform {
  id: string;
  name: string;
  parentId: string | null;
  sortOrder: number;
  isActive: boolean;
  children: Platform[];
}

interface PlatformModalProps {
  platform: Platform | null;
  platforms: Platform[];
  onClose: () => void;
  onSubmit: (data: {
    name: string;
    parentId?: string | null;
    sortOrder?: number;
    isActive?: boolean;
  }) => void;
}

export function PlatformModal({
  platform,
  platforms,
  onClose,
  onSubmit,
}: PlatformModalProps) {
  const [name, setName] = useState("");
  const [parentId, setParentId] = useState<string | null>(null);
  const [sortOrder, setSortOrder] = useState(0);
  const [isActive, setIsActive] = useState(true);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (platform) {
      setName(platform.name);
      setParentId(platform.parentId);
      setSortOrder(platform.sortOrder);
      setIsActive(platform.isActive);
    } else {
      setName("");
      setParentId(null);
      setSortOrder(0);
      setIsActive(true);
    }
  }, [platform]);

  // Flatten platforms for parent selector
  const flattenPlatforms = (
    platforms: Platform[],
    prefix = ""
  ): Array<{ id: string; name: string; depth: number }> => {
    const result: Array<{ id: string; name: string; depth: number }> = [];

    for (const p of platforms) {
      // Don't show current platform or its descendants as parent options
      if (platform && (p.id === platform.id || isDescendant(p, platform.id, platforms))) {
        continue;
      }

      result.push({ id: p.id, name: prefix + p.name, depth: prefix.length / 2 });

      if (p.children && p.children.length > 0) {
        result.push(...flattenPlatforms(p.children, prefix + p.name + " / "));
      }
    }

    return result;
  };

  const isDescendant = (
    platform: Platform,
    targetId: string,
    allPlatforms: Platform[]
  ): boolean => {
    if (platform.id === targetId) return true;

    for (const child of platform.children || []) {
      if (isDescendant(child, targetId, allPlatforms)) return true;
    }

    return false;
  };

  const flatPlatforms = flattenPlatforms(platforms);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!name.trim()) {
      alert("Name is required");
      return;
    }

    setSubmitting(true);
    await onSubmit({
      name: name.trim(),
      parentId,
      sortOrder,
      isActive,
    });
    setSubmitting(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <div className="bg-slate-800 rounded-lg border border-slate-700 w-full max-w-md p-6">
        <h2 className="text-xl font-bold text-white mb-4">
          {platform ? "Edit Platform" : "Add Platform"}
        </h2>

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Name */}
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">
              Name *
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full px-3 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="e.g., Steam, PlayStation"
              required
            />
          </div>

          {/* Parent */}
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">
              Parent Platform
            </label>
            <select
              value={parentId || ""}
              onChange={(e) => setParentId(e.target.value || null)}
              className="w-full px-3 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="">None (Root Level)</option>
              {flatPlatforms.map((p) => (
                <option key={p.id} value={p.id}>
                  {"\u00A0".repeat(p.depth * 2)}{p.name}
                </option>
              ))}
            </select>
          </div>

          {/* Sort Order */}
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">
              Sort Order
            </label>
            <input
              type="number"
              value={sortOrder}
              onChange={(e) => setSortOrder(parseInt(e.target.value) || 0)}
              className="w-full px-3 py-2 bg-slate-900 border border-slate-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            <p className="text-xs text-slate-500 mt-1">
              Lower numbers appear first
            </p>
          </div>

          {/* Active */}
          <div className="flex items-center gap-2">
            <input
              type="checkbox"
              id="isActive"
              checked={isActive}
              onChange={(e) => setIsActive(e.target.checked)}
              className="w-4 h-4 rounded border-slate-600 bg-slate-900 text-blue-600 focus:ring-2 focus:ring-blue-500"
            />
            <label htmlFor="isActive" className="text-sm text-slate-300">
              Active
            </label>
          </div>

          {/* Actions */}
          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-slate-300 hover:text-white transition-colors"
              disabled={submitting}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={submitting}
              className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors disabled:opacity-50"
            >
              {submitting ? "Saving..." : platform ? "Save Changes" : "Create Platform"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

/**
 * Platform Tree Select Component
 *
 * Tree multi-select for choosing platforms
 */

"use client";

import { useState, useEffect } from "react";

interface Platform {
  id: string;
  name: string;
  parentId: string | null;
  sortOrder: number;
  isActive: boolean;
  children: Platform[];
}

interface PlatformTreeSelectProps {
  value: string[]; // Array of selected platform IDs
  onChange: (platformIds: string[]) => void;
  disabled?: boolean;
}

export function PlatformTreeSelect({ value, onChange, disabled = false }: PlatformTreeSelectProps) {
  const [platforms, setPlatforms] = useState<Platform[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedNodes, setExpandedNodes] = useState<Set<string>>(new Set());

  useEffect(() => {
    fetchPlatforms();
  }, []);

  const fetchPlatforms = async () => {
    try {
      const res = await fetch("/api/platforms?asTree=true");
      const data = await res.json();
      if (data.success) {
        setPlatforms(data.data);
        // Auto-expand root nodes
        const rootIds = data.data
          .filter((p: Platform) => !p.parentId)
          .map((p: Platform) => p.id);
        setExpandedNodes(new Set(rootIds));
      }
    } catch (err) {
      console.error("Failed to load platforms", err);
    } finally {
      setLoading(false);
    }
  };

  const toggleExpand = (nodeId: string) => {
    setExpandedNodes((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(nodeId)) {
        newSet.delete(nodeId);
      } else {
        newSet.add(nodeId);
      }
      return newSet;
    });
  };

  const toggleSelection = (platformId: string) => {
    if (disabled) return;

    if (value.includes(platformId)) {
      onChange(value.filter((id) => id !== platformId));
    } else {
      onChange([...value, platformId]);
    }
  };

  const isNodeSelected = (node: Platform): boolean => {
    if (value.includes(node.id)) return true;
    // Check if any descendant is selected
    for (const child of node.children || []) {
      if (isNodeSelected(child)) return true;
    }
    return false;
  };

  const isPartiallySelected = (node: Platform): boolean => {
    if (value.includes(node.id)) return true;
    // Check if any descendant is selected
    for (const child of node.children || []) {
      if (isPartiallySelected(child)) return true;
    }
    return false;
  };

  const renderNode = (node: Platform, depth: number = 0): React.ReactNode => {
    const isExpanded = expandedNodes.has(node.id);
    const isSelected = value.includes(node.id);
    const isPartially = !isSelected && isPartiallySelected(node);
    const hasChildren = node.children && node.children.length > 0;

    return (
      <div key={node.id}>
        <div
          className={`flex items-center gap-1 py-1.5 px-2 rounded hover:bg-slate-700/50 ${
            isSelected ? "bg-blue-900/30" : ""
          }`}
          style={{ paddingLeft: `${depth * 16 + 8}px` }}
        >
          {/* Expand/Collapse */}
          {hasChildren ? (
            <button
              type="button"
              onClick={(e) => {
                e.preventDefault();
                toggleExpand(node.id);
              }}
              className="p-0.5 hover:bg-slate-600 rounded transition-colors"
            >
              <svg
                className={`w-3 h-3 text-slate-400 transition-transform ${
                  isExpanded ? "rotate-90" : ""
                }`}
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M9 5l7 7-7 7"
                />
              </svg>
            </button>
          ) : (
            <div className="w-4" />
          )}

          {/* Checkbox */}
          <button
            type="button"
            onClick={() => toggleSelection(node.id)}
            disabled={disabled}
            className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${
              disabled
                ? "bg-slate-700 cursor-not-allowed"
                : isSelected
                ? "bg-blue-600 border-blue-500"
                : isPartially
                ? "bg-blue-600/50 border-blue-500"
                : "bg-slate-700 border-slate-600 hover:border-slate-500"
            }`}
          >
            {isSelected && (
              <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
              </svg>
            )}
            {(isPartially || !isSelected) && !disabled && (
              <div
                className={`w-2 h-2 rounded-sm ${
                  isPartially ? "bg-white" : "bg-transparent"
                }`}
              />
            )}
          </button>

          {/* Platform Name */}
          <span
            className={`text-sm flex-1 truncate ${
              !node.isActive ? "text-slate-500 line-through" : "text-white"
            }`}
          >
            {node.name}
          </span>
        </div>

        {/* Children */}
        {hasChildren && isExpanded && (
          <div>
            {node.children!.map((child) => renderNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  // Get selected platform info
  const getSelectedPlatforms = (nodes: Platform[]): Platform[] => {
    const result: Platform[] = [];
    for (const node of nodes) {
      if (value.includes(node.id)) {
        result.push(node);
      }
      if (node.children) {
        result.push(...getSelectedPlatforms(node.children));
      }
    }
    return result;
  };

  const selectedPlatforms = getSelectedPlatforms(platforms);

  return (
    <div className="border border-slate-700 rounded-lg bg-slate-900">
      {/* Selected platforms chips */}
      {selectedPlatforms.length > 0 && (
        <div className="flex flex-wrap gap-2 p-3 border-b border-slate-700">
          {selectedPlatforms.map((p) => (
            <span
              key={p.id}
              className="inline-flex items-center gap-1 px-2 py-1 bg-blue-900/50 text-blue-300 text-sm rounded"
            >
              {p.name}
              {!disabled && (
                <button
                  onClick={() => toggleSelection(p.id)}
                  className="hover:text-red-300"
                  type="button"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M6 18L18 6M6 6l12 12"
                    />
                  </svg>
                </button>
              )}
            </span>
          ))}
        </div>
      )}

      {/* Platform tree */}
      <div className="p-3 max-h-64 overflow-y-auto">
        {loading ? (
          <div className="text-center text-slate-400 py-4">Loading platforms...</div>
        ) : platforms.length === 0 ? (
          <div className="text-center text-slate-400 py-4">
            No platforms available.{" "}
            <a href="/dashboard/platforms" className="text-blue-400 hover:underline">
              Create platforms first
            </a>
          </div>
        ) : (
          <div>
            {platforms.map((node) => renderNode(node))}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

/**
 * Products Table Component
 *
 * Displays list of products with actions
 */

import { useEffect, useState } from "react";
import Link from "next/link";

interface Product {
  id: string;
  name: string;
  slug: string;
  price: string;
  isActive: boolean;
  stockCount: number;
  totalSold: number;
  averageRating: string | null;
  reviewCount: number;
  createdAt: string;
}

export function ProductsTable() {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  useEffect(() => {
    async function fetchProducts() {
      try {
        const params = new URLSearchParams({
          page: page.toString(),
          limit: "20",
        });
        if (search) params.set("search", search);

        const response = await fetch(`/api/products?${params}`);
        const result = await response.json();

        if (result.success) {
          setProducts(result.data);
          setTotalPages(result.pagination.totalPages);
        } else {
          setError(result.error || "Failed to load products");
        }
      } catch (err) {
        setError("Network error");
      } finally {
        setLoading(false);
      }
    }

    fetchProducts();
  }, [page, search]);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setPage(1);
  };

  const formatCurrency = (amount: string) => {
    return new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: "USD",
    }).format(parseFloat(amount || "0"));
  };

  if (loading) {
    return (
      <div className="bg-slate-900 rounded-lg shadow-sm p-6 border border-slate-800">
        <div className="animate-pulse space-y-4">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="h-12 bg-slate-800 rounded" />
          ))}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-950/50 text-red-400 border border-red-900 p-4 rounded-lg">
        Error loading products: {error}
      </div>
    );
  }

  return (
    <div className="bg-slate-900 rounded-lg shadow-sm overflow-hidden border border-slate-800">
      {/* Search */}
      <form onSubmit={handleSearch} className="p-4 border-b border-slate-800">
        <div className="flex gap-4">
          <input
            type="text"
            placeholder="Search products..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="flex-1 px-4 py-2 bg-slate-800 border border-slate-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-white placeholder-slate-500"
          />
          <button
            type="submit"
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
          >
            Search
          </button>
        </div>
      </form>

      {/* Table */}
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead className="bg-slate-800">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Product
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Price
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Stock
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Sold
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Rating
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-slate-400 uppercase">
                Status
              </th>
              <th className="px-6 py-3 text-right text-xs font-medium text-slate-400 uppercase">
                Actions
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {products.map((product) => (
              <tr key={product.id} className="hover:bg-slate-800">
                <td className="px-6 py-4">
                  <div>
                    <p className="font-medium text-white">{product.name}</p>
                    <p className="text-sm text-slate-500">{product.slug}</p>
                  </div>
                </td>
                <td className="px-6 py-4 text-slate-300">
                  {formatCurrency(product.price)}
                </td>
                <td className="px-6 py-4">
                  <span
                    className={`px-2 py-1 rounded text-sm ${
                      product.stockCount < 5
                        ? "bg-red-950 text-red-400 border border-red-900"
                        : "bg-green-950 text-green-400 border border-green-900"
                    }`}
                  >
                    {product.stockCount}
                  </span>
                </td>
                <td className="px-6 py-4 text-slate-300">
                  {product.totalSold}
                </td>
                <td className="px-6 py-4 text-slate-300">
                  {product.averageRating ? (
                    <span>
                      {parseFloat(product.averageRating).toFixed(1)}
                      <span className="text-slate-500">
                        ({product.reviewCount})
                      </span>
                    </span>
                  ) : (
                    <span className="text-slate-600">No reviews</span>
                  )}
                </td>
                <td className="px-6 py-4">
                  <span
                    className={`px-2 py-1 rounded text-sm ${
                      product.isActive
                        ? "bg-green-950 text-green-400 border border-green-900"
                        : "bg-slate-800 text-slate-400 border border-slate-700"
                    }`}
                  >
                    {product.isActive ? "Active" : "Inactive"}
                  </span>
                </td>
                <td className="px-6 py-4 text-right">
                  <Link
                    href={`/dashboard/products/${product.id}`}
                    className="text-blue-400 hover:text-blue-300 text-sm"
                  >
                    Edit
                  </Link>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="px-6 py-4 border-t border-slate-800 flex items-center justify-between">
          <p className="text-sm text-slate-500">
            Page {page} of {totalPages}
          </p>
          <div className="flex gap-2">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="px-4 py-2 border border-slate-700 text-slate-300 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-800"
            >
              Previous
            </button>
            <button
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              className="px-4 py-2 border border-slate-700 text-slate-300 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-800"
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

/**
 * Reviews Table Component
 *
 * Displays customer product reviews
 */

import { useEffect, useState } from "react";

interface Review {
  id: string;
  productId: string;
  productName: string;
  productSlug: string;
  customerEmail: string;
  rating: number;
  comment: string | null;
  isVerifiedPurchase: boolean;
  isActive: boolean;
  createdAt: string;
}

export function ReviewsTable() {
  const [reviews, setReviews] = useState<Review[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<string>("");
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  useEffect(() => {
    async function fetchReviews() {
      try {
        const params = new URLSearchParams({
          page: page.toString(),
          limit: "20",
        });
        if (activeFilter !== "") params.set("isActive", activeFilter);

        const response = await fetch(`/api/reviews?${params}`);
        const result = await response.json();

        if (result.success) {
          setReviews(result.data);
          setTotalPages(result.pagination.totalPages);
        } else {
          setError(result.error || "Failed to load reviews");
        }
      } catch (err) {
        setError("Network error");
      } finally {
        setLoading(false);
      }
    }

    fetchReviews();
  }, [page, activeFilter]);

  const renderStars = (rating: number) => {
    return (
